{
  "name": "Employee of the Month Platform",
  "description": "A comprehensive nomination and voting platform for organizations to recognize outstanding employees. Features include role-based access for employees and admins, voting cycle management, real-time results visualization, and secure local data handling."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum UserRole {
  ADMIN = 'ADMIN',
  EMPLOYEE = 'EMPLOYEE'
}

export interface User {
  id: string;
  name: string;
  email: string;
  role: UserRole;
  department: string;
  avatar?: string;
}

export enum CycleStatus {
  NOMINATION = 'NOMINATION', // Users can nominate
  VOTING = 'VOTING',         // Users can vote
  CLOSED = 'CLOSED'          // Read-only results
}

export interface Cycle {
  id: string;
  month: number; // 0-11
  year: number;
  status: CycleStatus;
  winnerId?: string;
}

export interface Nomination {
  id: string;
  nominatorId: string;
  nomineeId: string;
  cycleId: string;
  reason: string;
  timestamp: number;
}

export interface Vote {
  id: string;
  voterId: string;
  nomineeId: string;
  cycleId: string;
  timestamp: number;
}

export interface AuthState {
  user: User | null;
  isAuthenticated: boolean;
}

export interface CycleStats {
  nomineeId: string;
  nomineeName: string;
  nominationCount: number;
  voteCount: number;
}

import { User, UserRole, Cycle, CycleStatus, Nomination, Vote, CycleStats } from '../types';

// Initial Mock Data
const INITIAL_USERS: User[] = [
  { id: 'u1', name: 'Admin User', email: 'admin@company.com', role: UserRole.ADMIN, department: 'Management' },
  { id: 'u2', name: 'Jane Doe', email: 'jane@company.com', role: UserRole.EMPLOYEE, department: 'Engineering' },
  { id: 'u3', name: 'John Smith', email: 'john@company.com', role: UserRole.EMPLOYEE, department: 'Marketing' },
  { id: 'u4', name: 'Alice Johnson', email: 'alice@company.com', role: UserRole.EMPLOYEE, department: 'HR' },
  { id: 'u5', name: 'Bob Williams', email: 'bob@company.com', role: UserRole.EMPLOYEE, department: 'Engineering' },
  { id: 'u6', name: 'Charlie Brown', email: 'charlie@company.com', role: UserRole.EMPLOYEE, department: 'Sales' },
];

const INITIAL_CYCLES: Cycle[] = [
  { id: 'c1', month: new Date().getMonth(), year: new Date().getFullYear(), status: CycleStatus.NOMINATION },
];

// Helper to access LocalStorage safely
const getStorage = <T,>(key: string, initial: T): T => {
  const stored = localStorage.getItem(key);
  if (!stored) {
    localStorage.setItem(key, JSON.stringify(initial));
    return initial;
  }
  return JSON.parse(stored);
};

const setStorage = <T,>(key: string, value: T): void => {
  localStorage.setItem(key, JSON.stringify(value));
};

// Database Service Simulation
export const mockDb = {
  getUsers: (): User[] => getStorage('users', INITIAL_USERS),

  getUserById: (id: string): User | undefined => {
    const users = getStorage<User[]>('users', INITIAL_USERS);
    return users.find(u => u.id === id);
  },

  getEmployees: (): User[] => {
    return getStorage<User[]>('users', INITIAL_USERS).filter(u => u.role === UserRole.EMPLOYEE);
  },

  getCycles: (): Cycle[] => getStorage('cycles', INITIAL_CYCLES),

  getActiveCycle: (): Cycle | undefined => {
    const cycles = getStorage<Cycle[]>('cycles', INITIAL_CYCLES);
    // Find open cycle or most recent one
    return cycles.find(c => c.status !== CycleStatus.CLOSED) || cycles[cycles.length - 1];
  },

  createCycle: (month: number, year: number): Cycle => {
    const cycles = getStorage<Cycle[]>('cycles', INITIAL_CYCLES);
    // Deactivate previous active cycles
    const updatedCycles = cycles.map(c => 
      c.status !== CycleStatus.CLOSED ? { ...c, status: CycleStatus.CLOSED } : c
    );

    const newCycle: Cycle = {
      id: `c${Date.now()}`,
      month,
      year,
      status: CycleStatus.NOMINATION
    };

    updatedCycles.push(newCycle);
    setStorage('cycles', updatedCycles);
    return newCycle;
  },

  updateCycleStatus: (cycleId: string, status: CycleStatus): void => {
    const cycles = getStorage<Cycle[]>('cycles', INITIAL_CYCLES);
    const updated = cycles.map(c => c.id === cycleId ? { ...c, status } : c);
    setStorage('cycles', updated);
  },

  getNominations: (cycleId: string): Nomination[] => {
    const all = getStorage<Nomination[]>('nominations', []);
    return all.filter(n => n.cycleId === cycleId);
  },

  getUserNomination: (userId: string, cycleId: string): Nomination | undefined => {
    const all = getStorage<Nomination[]>('nominations', []);
    return all.find(n => n.nominatorId === userId && n.cycleId === cycleId);
  },

  addNomination: (nominatorId: string, nomineeId: string, cycleId: string, reason: string): void => {
    const all = getStorage<Nomination[]>('nominations', []);
    if (all.find(n => n.nominatorId === nominatorId && n.cycleId === cycleId)) {
      throw new Error("You have already nominated someone this cycle.");
    }
    const newNomination: Nomination = {
      id: `n${Date.now()}`,
      nominatorId,
      nomineeId,
      cycleId,
      reason,
      timestamp: Date.now()
    };
    all.push(newNomination);
    setStorage('nominations', all);
  },

  getVotes: (cycleId: string): Vote[] => {
    const all = getStorage<Vote[]>('votes', []);
    return all.filter(v => v.cycleId === cycleId);
  },

  getUserVote: (userId: string, cycleId: string): Vote | undefined => {
    const all = getStorage<Vote[]>('votes', []);
    return all.find(v => v.voterId === userId && v.cycleId === cycleId);
  },

  addVote: (voterId: string, nomineeId: string, cycleId: string): void => {
    const all = getStorage<Vote[]>('votes', []);
    if (all.find(v => v.voterId === voterId && v.cycleId === cycleId)) {
      throw new Error("You have already voted this cycle.");
    }
    const newVote: Vote = {
      id: `v${Date.now()}`,
      voterId,
      nomineeId,
      cycleId,
      timestamp: Date.now()
    };
    all.push(newVote);
    setStorage('votes', all);
  },

  getCycleStats: (cycleId: string): CycleStats[] => {
    const nominations = getStorage<Nomination[]>('nominations', []).filter(n => n.cycleId === cycleId);
    const votes = getStorage<Vote[]>('votes', []).filter(v => v.cycleId === cycleId);
    const employees = getStorage<User[]>('users', INITIAL_USERS);

    const statsMap = new Map<string, CycleStats>();

    // Initialize for all employees who received at least one nomination
    nominations.forEach(nom => {
      if (!statsMap.has(nom.nomineeId)) {
        const emp = employees.find(e => e.id === nom.nomineeId);
        if (emp) {
          statsMap.set(nom.nomineeId, {
            nomineeId: emp.id,
            nomineeName: emp.name,
            nominationCount: 0,
            voteCount: 0
          });
        }
      }
      const stat = statsMap.get(nom.nomineeId);
      if (stat) stat.nominationCount++;
    });

    // Count votes
    votes.forEach(vote => {
       // Only count votes if the person was nominated (optional rule, but good for structure)
       // Or simply count all votes. Let's count all votes but ensure they map to a user
       if (!statsMap.has(vote.nomineeId)) {
         const emp = employees.find(e => e.id === vote.nomineeId);
         if (emp) {
            statsMap.set(vote.nomineeId, {
              nomineeId: emp.id,
              nomineeName: emp.name,
              nominationCount: 0,
              voteCount: 0
            });
         }
       }
       const stat = statsMap.get(vote.nomineeId);
       if (stat) stat.voteCount++;
    });

    return Array.from(statsMap.values()).sort((a, b) => b.voteCount - a.voteCount);
  }
};

import React, { createContext, useContext, useState, useEffect, ReactNode } from 'react';
import { User, AuthState } from '../types';
import { mockDb } from '../services/mockDb';

interface AuthContextType extends AuthState {
  login: (email: string) => Promise<boolean>;
  logout: () => void;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export const AuthProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [state, setState] = useState<AuthState>({
    user: null,
    isAuthenticated: false,
  });

  useEffect(() => {
    const storedUserId = localStorage.getItem('auth_user_id');
    if (storedUserId) {
      const user = mockDb.getUserById(storedUserId);
      if (user) {
        setState({ user, isAuthenticated: true });
      }
    }
  }, []);

  const login = async (email: string): Promise<boolean> => {
    // Simulating API latency
    await new Promise(resolve => setTimeout(resolve, 500));

    const users = mockDb.getUsers();
    const user = users.find(u => u.email === email);

    if (user) {
      localStorage.setItem('auth_user_id', user.id);
      setState({ user, isAuthenticated: true });
      return true;
    }
    return false;
  };

  const logout = () => {
    localStorage.removeItem('auth_user_id');
    setState({ user: null, isAuthenticated: false });
  };

  return (
    <AuthContext.Provider value={{ ...state, login, logout }}>
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
};

import React from 'react';
import { useAuth } from '../context/AuthContext';
import { UserRole } from '../types';
import { LogOut, LayoutDashboard, UserCheck, Vote, Medal, Menu, X } from 'lucide-react';
import { Link, useLocation } from 'react-router-dom';

export const Layout: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const { user, logout } = useAuth();
  const location = useLocation();
  const [isMobileMenuOpen, setIsMobileMenuOpen] = React.useState(false);

  if (!user) {
    return <div className="min-h-screen bg-gray-50">{children}</div>;
  }

  const isActive = (path: string) => location.pathname === path;

  const NavItem = ({ to, icon: Icon, label }: { to: string; icon: any; label: string }) => (
    <Link
      to={to}
      className={`flex items-center px-4 py-3 text-sm font-medium transition-colors rounded-lg mb-1 ${
        isActive(to)
          ? 'bg-indigo-50 text-indigo-700'
          : 'text-gray-600 hover:bg-gray-100 hover:text-gray-900'
      }`}
      onClick={() => setIsMobileMenuOpen(false)}
    >
      <Icon className="w-5 h-5 mr-3" />
      {label}
    </Link>
  );

  return (
    <div className="min-h-screen bg-gray-50 flex flex-col md:flex-row">
      {/* Mobile Header */}
      <div className="md:hidden bg-white shadow-sm p-4 flex justify-between items-center z-20">
        <div className="flex items-center font-bold text-indigo-600">
          <Medal className="w-6 h-6 mr-2" />
          <span>EOTM Platform</span>
        </div>
        <button onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}>
          {isMobileMenuOpen ? <X className="w-6 h-6" /> : <Menu className="w-6 h-6" />}
        </button>
      </div>

      {/* Sidebar Navigation */}
      <aside 
        className={`fixed md:sticky top-0 h-screen w-64 bg-white border-r border-gray-200 transform transition-transform duration-200 ease-in-out z-10 
        ${isMobileMenuOpen ? 'translate-x-0' : '-translate-x-full md:translate-x-0'} flex flex-col`}
      >
        <div className="p-6 border-b border-gray-100 hidden md:flex items-center">
          <Medal className="w-8 h-8 text-indigo-600 mr-3" />
          <h1 className="text-xl font-bold text-gray-900">EOTM</h1>
        </div>

        <div className="p-6 border-b border-gray-100 bg-indigo-50/50">
          <div className="flex items-center">
            <div className="w-10 h-10 rounded-full bg-indigo-100 flex items-center justify-center text-indigo-700 font-bold text-lg">
              {user.name.charAt(0)}
            </div>
            <div className="ml-3">
              <p className="text-sm font-medium text-gray-900">{user.name}</p>
              <p className="text-xs text-gray-500 capitalize">{user.role.toLowerCase()}</p>
            </div>
          </div>
        </div>

        <nav className="flex-1 p-4 overflow-y-auto">
          <div className="space-y-1">
            <NavItem to="/" icon={LayoutDashboard} label="Dashboard" />

            {user.role === UserRole.ADMIN && (
              <NavItem to="/admin" icon={UserCheck} label="Admin Panel" />
            )}

            <div className="pt-4 mt-4 border-t border-gray-100">
              <p className="px-4 text-xs font-semibold text-gray-400 uppercase tracking-wider mb-2">
                Actions
              </p>
              <NavItem to="/nominate" icon={UserCheck} label="Nominate" />
              <NavItem to="/vote" icon={Vote} label="Vote" />
            </div>
          </div>
        </nav>

        <div className="p-4 border-t border-gray-200">
          <button
            onClick={logout}
            className="flex items-center w-full px-4 py-2 text-sm font-medium text-red-600 rounded-lg hover:bg-red-50 transition-colors"
          >
            <LogOut className="w-5 h-5 mr-3" />
            Sign Out
          </button>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 p-4 md:p-8 overflow-y-auto">
        <div className="max-w-5xl mx-auto">
          {children}
        </div>
      </main>

      {/* Mobile Overlay */}
      {isMobileMenuOpen && (
        <div 
          className="fixed inset-0 bg-black bg-opacity-50 z-0 md:hidden"
          onClick={() => setIsMobileMenuOpen(false)}
        ></div>
      )}
    </div>
  );
};

import React, { useState } from 'react';
import { useAuth } from '../context/AuthContext';
import { Medal, Lock, User } from 'lucide-react';
import { useNavigate } from 'react-router-dom';

export const Login: React.FC = () => {
  const [email, setEmail] = useState('');
  const [error, setError] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const { login } = useAuth();
  const navigate = useNavigate();

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setIsLoading(true);

    try {
      const success = await login(email);
      if (success) {
        navigate('/');
      } else {
        setError('Invalid email address. Try admin@company.com or jane@company.com');
      }
    } catch (err) {
      setError('An error occurred during login');
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-indigo-100 to-white flex items-center justify-center p-4">
      <div className="max-w-md w-full bg-white rounded-2xl shadow-xl overflow-hidden">
        <div className="bg-indigo-600 p-8 text-center">
          <div className="inline-flex items-center justify-center w-16 h-16 rounded-full bg-white/20 mb-4">
            <Medal className="w-8 h-8 text-white" />
          </div>
          <h1 className="text-2xl font-bold text-white">Employee of the Month</h1>
          <p className="text-indigo-100 mt-2">Nomination & Voting Platform</p>
        </div>

        <div className="p-8">
          <form onSubmit={handleSubmit} className="space-y-6">
            <div>
              <label htmlFor="email" className="block text-sm font-medium text-gray-700 mb-1">
                Email Address
              </label>
              <div className="relative">
                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                  <User className="h-5 w-5 text-gray-400" />
                </div>
                <input
                  id="email"
                  type="email"
                  required
                  className="block w-full pl-10 pr-3 py-2 border border-gray-300 rounded-lg focus:ring-indigo-500 focus:border-indigo-500 transition-colors"
                  placeholder="name@company.com"
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                />
              </div>
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">
                Password
              </label>
              <div className="relative">
                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                  <Lock className="h-5 w-5 text-gray-400" />
                </div>
                <input
                  type="password"
                  disabled
                  className="block w-full pl-10 pr-3 py-2 border border-gray-300 rounded-lg bg-gray-50 text-gray-500 cursor-not-allowed"
                  value="password123" 
                />
              </div>
              <p className="mt-1 text-xs text-gray-500">Password is auto-filled for demo purposes.</p>
            </div>

            {error && (
              <div className="bg-red-50 text-red-600 text-sm p-3 rounded-lg border border-red-100">
                {error}
              </div>
            )}

            <button
              type="submit"
              disabled={isLoading}
              className="w-full flex justify-center py-2.5 px-4 border border-transparent rounded-lg shadow-sm text-sm font-medium text-white bg-indigo-600 hover:bg-indigo-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-indigo-500 disabled:opacity-70 disabled:cursor-not-allowed transition-all"
            >
              {isLoading ? 'Signing in...' : 'Sign In'}
            </button>
          </form>

          <div className="mt-6 pt-6 border-t border-gray-100">
            <h4 className="text-xs font-semibold text-gray-500 uppercase tracking-wider mb-3">
              Demo Credentials
            </h4>
            <div className="grid grid-cols-2 gap-3">
              <button 
                onClick={() => setEmail('admin@company.com')}
                className="text-xs p-2 bg-gray-50 hover:bg-gray-100 rounded text-left border border-gray-200 transition-colors"
              >
                <span className="font-bold block text-gray-900">Admin</span>
                admin@company.com
              </button>
              <button 
                onClick={() => setEmail('jane@company.com')}
                className="text-xs p-2 bg-gray-50 hover:bg-gray-100 rounded text-left border border-gray-200 transition-colors"
              >
                <span className="font-bold block text-gray-900">Employee</span>
                jane@company.com
              </button>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useEffect, useState } from 'react';
import { useAuth } from '../context/AuthContext';
import { mockDb } from '../services/mockDb';
import { Cycle, CycleStatus, Nomination, Vote } from '../types';
import { Calendar, UserCheck, Vote as VoteIcon, AlertCircle, CheckCircle } from 'lucide-react';
import { Link } from 'react-router-dom';

const MONTHS = [
  'January', 'February', 'March', 'April', 'May', 'June',
  'July', 'August', 'September', 'October', 'November', 'December'
];

export const Dashboard: React.FC = () => {
  const { user } = useAuth();
  const [activeCycle, setActiveCycle] = useState<Cycle | undefined>(undefined);
  const [userNomination, setUserNomination] = useState<Nomination | undefined>(undefined);
  const [userVote, setUserVote] = useState<Vote | undefined>(undefined);

  useEffect(() => {
    const cycle = mockDb.getActiveCycle();
    setActiveCycle(cycle);

    if (user && cycle) {
      setUserNomination(mockDb.getUserNomination(user.id, cycle.id));
      setUserVote(mockDb.getUserVote(user.id, cycle.id));
    }
  }, [user]);

  if (!activeCycle) {
    return (
      <div className="p-8 text-center bg-white rounded-xl shadow-sm">
        <div className="inline-flex items-center justify-center w-12 h-12 rounded-full bg-gray-100 mb-4">
          <Calendar className="w-6 h-6 text-gray-400" />
        </div>
        <h3 className="text-lg font-medium text-gray-900">No Active Cycles</h3>
        <p className="text-gray-500 mt-2">There are currently no active voting cycles. Please check back later.</p>
      </div>
    );
  }

  const getStatusColor = (status: CycleStatus) => {
    switch (status) {
      case CycleStatus.NOMINATION: return 'bg-blue-100 text-blue-800';
      case CycleStatus.VOTING: return 'bg-green-100 text-green-800';
      case CycleStatus.CLOSED: return 'bg-gray-100 text-gray-800';
    }
  };

  return (
    <div className="space-y-6">
      <header className="flex flex-col md:flex-row md:items-center md:justify-between gap-4">
        <div>
          <h1 className="text-2xl font-bold text-gray-900">Welcome, {user?.name}</h1>
          <p className="text-gray-500">Here is your activity for the current cycle.</p>
        </div>
        <div className={`px-4 py-2 rounded-full font-medium text-sm inline-flex items-center self-start ${getStatusColor(activeCycle.status)}`}>
          <Calendar className="w-4 h-4 mr-2" />
          {MONTHS[activeCycle.month]} {activeCycle.year} - {activeCycle.status}
        </div>
      </header>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        {/* Nomination Status Card */}
        <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
          <div className="p-6">
            <div className="flex items-center justify-between mb-4">
              <div className="p-3 bg-indigo-50 rounded-lg">
                <UserCheck className="w-6 h-6 text-indigo-600" />
              </div>
              {userNomination ? (
                <CheckCircle className="w-6 h-6 text-green-500" />
              ) : (
                <div className="w-6 h-6 rounded-full border-2 border-gray-200"></div>
              )}
            </div>
            <h3 className="text-lg font-bold text-gray-900 mb-2">Nomination</h3>
            <p className="text-gray-600 mb-6 min-h-[3rem]">
              {userNomination 
                ? "You have successfully submitted your nomination for this cycle."
                : activeCycle.status === CycleStatus.NOMINATION 
                  ? "Nominate a deserving colleague for their outstanding work."
                  : "Nominations are currently closed for this cycle."
              }
            </p>

            {userNomination ? (
               <button disabled className="w-full py-2 px-4 bg-gray-100 text-gray-400 rounded-lg font-medium cursor-not-allowed">
                 Nomination Submitted
               </button>
            ) : (
              <Link 
                to="/nominate"
                className={`block w-full text-center py-2 px-4 rounded-lg font-medium transition-colors ${
                  activeCycle.status === CycleStatus.NOMINATION
                    ? 'bg-indigo-600 text-white hover:bg-indigo-700'
                    : 'bg-gray-100 text-gray-400 cursor-not-allowed pointer-events-none'
                }`}
              >
                Make a Nomination
              </Link>
            )}
          </div>
        </div>

        {/* Voting Status Card */}
        <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
          <div className="p-6">
            <div className="flex items-center justify-between mb-4">
              <div className="p-3 bg-purple-50 rounded-lg">
                <VoteIcon className="w-6 h-6 text-purple-600" />
              </div>
              {userVote ? (
                <CheckCircle className="w-6 h-6 text-green-500" />
              ) : (
                <div className="w-6 h-6 rounded-full border-2 border-gray-200"></div>
              )}
            </div>
            <h3 className="text-lg font-bold text-gray-900 mb-2">Voting</h3>
            <p className="text-gray-600 mb-6 min-h-[3rem]">
              {userVote
                ? "Thank you for casting your vote."
                : activeCycle.status === CycleStatus.VOTING
                  ? "Cast your vote for the final candidates."
                  : activeCycle.status === CycleStatus.NOMINATION
                    ? "Voting will open once the nomination phase is complete."
                    : "Voting is closed."
              }
            </p>

            {userVote ? (
               <button disabled className="w-full py-2 px-4 bg-gray-100 text-gray-400 rounded-lg font-medium cursor-not-allowed">
                 Vote Submitted
               </button>
            ) : (
              <Link 
                to="/vote"
                className={`block w-full text-center py-2 px-4 rounded-lg font-medium transition-colors ${
                  activeCycle.status === CycleStatus.VOTING
                    ? 'bg-purple-600 text-white hover:bg-purple-700'
                    : 'bg-gray-100 text-gray-400 cursor-not-allowed pointer-events-none'
                }`}
              >
                Cast Vote
              </Link>
            )}
          </div>
        </div>
      </div>

      <div className="bg-blue-50 border border-blue-100 rounded-xl p-4 flex items-start">
        <AlertCircle className="w-5 h-5 text-blue-600 mt-0.5 mr-3 flex-shrink-0" />
        <div>
          <h4 className="font-semibold text-blue-900">How it works</h4>
          <ul className="mt-2 text-sm text-blue-800 list-disc list-inside space-y-1">
            <li>Nominations are anonymous.</li>
            <li>You can only nominate one person per cycle.</li>
            <li>Voting opens after the nomination phase ends.</li>
            <li>You cannot nominate or vote for yourself (System integrity).</li>
          </ul>
        </div>
      </div>
    </div>
  );
};

import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { mockDb } from '../services/mockDb';
import { Cycle, CycleStatus, User } from '../types';
import { ArrowLeft, Send } from 'lucide-react';

export const Nominate: React.FC = () => {
  const navigate = useNavigate();
  const { user } = useAuth();
  const [activeCycle, setActiveCycle] = useState<Cycle | undefined>();
  const [employees, setEmployees] = useState<User[]>([]);
  const [selectedNominee, setSelectedNominee] = useState('');
  const [reason, setReason] = useState('');
  const [error, setError] = useState('');
  const [success, setSuccess] = useState(false);

  useEffect(() => {
    const cycle = mockDb.getActiveCycle();
    setActiveCycle(cycle);

    // Filter out current user from potential nominees
    const allEmployees = mockDb.getEmployees().filter(e => e.id !== user?.id);
    setEmployees(allEmployees);

    // Check if already nominated
    if (user && cycle) {
      const existing = mockDb.getUserNomination(user.id, cycle.id);
      if (existing) {
        setSuccess(true);
      }
    }
  }, [user]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!activeCycle || !user) return;

    try {
      mockDb.addNomination(user.id, selectedNominee, activeCycle.id, reason);
      setSuccess(true);
      setTimeout(() => navigate('/'), 2000);
    } catch (err: any) {
      setError(err.message);
    }
  };

  if (!activeCycle || activeCycle.status !== CycleStatus.NOMINATION) {
    return (
      <div className="text-center py-12">
        <h2 className="text-xl font-bold text-gray-900">Nominations Closed</h2>
        <p className="text-gray-500 mt-2">The nomination phase is currently inactive.</p>
        <button onClick={() => navigate('/')} className="mt-4 text-indigo-600 hover:text-indigo-800 font-medium">
          Return to Dashboard
        </button>
      </div>
    );
  }

  if (success) {
    return (
      <div className="max-w-xl mx-auto text-center py-12">
        <div className="w-16 h-16 bg-green-100 text-green-600 rounded-full flex items-center justify-center mx-auto mb-4">
          <Send className="w-8 h-8" />
        </div>
        <h2 className="text-2xl font-bold text-gray-900">Nomination Submitted!</h2>
        <p className="text-gray-600 mt-2">Thank you for recognizing your colleague's hard work.</p>
        <p className="text-gray-400 text-sm mt-4">Redirecting to dashboard...</p>
      </div>
    );
  }

  return (
    <div className="max-w-2xl mx-auto">
      <button 
        onClick={() => navigate('/')}
        className="flex items-center text-gray-500 hover:text-gray-700 mb-6 transition-colors"
      >
        <ArrowLeft className="w-4 h-4 mr-2" />
        Back to Dashboard
      </button>

      <div className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden">
        <div className="p-6 border-b border-gray-100">
          <h2 className="text-xl font-bold text-gray-900">Nominate a Colleague</h2>
          <p className="text-gray-500 text-sm mt-1">Select an employee and share why they deserve to be Employee of the Month.</p>
        </div>

        <form onSubmit={handleSubmit} className="p-6 space-y-6">
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">Select Nominee</label>
            <select
              required
              value={selectedNominee}
              onChange={(e) => setSelectedNominee(e.target.value)}
              className="w-full rounded-lg border-gray-300 shadow-sm focus:border-indigo-500 focus:ring-indigo-500 py-2.5"
            >
              <option value="">-- Choose an employee --</option>
              {employees.map(emp => (
                <option key={emp.id} value={emp.id}>
                  {emp.name} ({emp.department})
                </option>
              ))}
            </select>
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">Reason for Nomination</label>
            <textarea
              required
              value={reason}
              onChange={(e) => setReason(e.target.value)}
              rows={4}
              className="w-full rounded-lg border-gray-300 shadow-sm focus:border-indigo-500 focus:ring-indigo-500"
              placeholder="Describe their achievements, attitude, or specific contributions..."
            ></textarea>
            <p className="mt-2 text-xs text-gray-500">Your nomination is anonymous to the nominee, but visible to admins.</p>
          </div>

          {error && (
            <div className="p-4 bg-red-50 text-red-700 rounded-lg text-sm">
