import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { mockDb } from '../services/mockDb';
import { Cycle, CycleStatus, User, Nomination } from '../types';
import { ArrowLeft, CheckCircle } from 'lucide-react';

export const Vote: React.FC = () => {
  const navigate = useNavigate();
  const { user } = useAuth();
  const [activeCycle, setActiveCycle] = useState<Cycle | undefined>();
  const [candidates, setCandidates] = useState<{ user: User, nominations: number }[]>([]);
  const [selectedCandidate, setSelectedCandidate] = useState('');
  const [error, setError] = useState('');
  const [success, setSuccess] = useState(false);

  useEffect(() => {
    const cycle = mockDb.getActiveCycle();
    setActiveCycle(cycle);

    if (cycle && cycle.status === CycleStatus.VOTING) {
      // Get all nominations for this cycle
      const nominations = mockDb.getNominations(cycle.id);

      // Group nominations to find candidates
      const candidateMap = new Map<string, number>();
      nominations.forEach(n => {
        const count = candidateMap.get(n.nomineeId) || 0;
        candidateMap.set(n.nomineeId, count + 1);
      });

      // Filter out current user from candidates (prevent self-voting)
      const validCandidates: { user: User, nominations: number }[] = [];
      const employees = mockDb.getEmployees();

      candidateMap.forEach((count, id) => {
        if (id !== user?.id) {
           const emp = employees.find(e => e.id === id);
           if (emp) {
             validCandidates.push({ user: emp, nominations: count });
           }
        }
      });

      // Sort by nomination count (optional, but looks nice)
      validCandidates.sort((a, b) => b.nominations - a.nominations);
      setCandidates(validCandidates);
    }

    if (user && cycle) {
      const existing = mockDb.getUserVote(user.id, cycle.id);
      if (existing) {
        setSuccess(true);
      }
    }
  }, [user]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!activeCycle || !user || !selectedCandidate) return;

    try {
      mockDb.addVote(user.id, selectedCandidate, activeCycle.id);
      setSuccess(true);
      setTimeout(() => navigate('/'), 2000);
    } catch (err: any) {
      setError(err.message);
    }
  };

  if (!activeCycle || activeCycle.status !== CycleStatus.VOTING) {
    return (
      <div className="text-center py-12">
        <h2 className="text-xl font-bold text-gray-900">Voting Closed</h2>
        <p className="text-gray-500 mt-2">The voting phase is currently inactive.</p>
        <button onClick={() => navigate('/')} className="mt-4 text-indigo-600 hover:text-indigo-800 font-medium">
          Return to Dashboard
        </button>
      </div>
    );
  }

  if (success) {
    return (
      <div className="max-w-xl mx-auto text-center py-12">
        <div className="w-16 h-16 bg-purple-100 text-purple-600 rounded-full flex items-center justify-center mx-auto mb-4">
          <CheckCircle className="w-8 h-8" />
        </div>
        <h2 className="text-2xl font-bold text-gray-900">Vote Submitted!</h2>
        <p className="text-gray-600 mt-2">Your voice has been heard.</p>
        <p className="text-gray-400 text-sm mt-4">Redirecting to dashboard...</p>
      </div>
    );
  }

  return (
    <div className="max-w-4xl mx-auto">
      <button 
        onClick={() => navigate('/')}
        className="flex items-center text-gray-500 hover:text-gray-700 mb-6 transition-colors"
      >
        <ArrowLeft className="w-4 h-4 mr-2" />
        Back to Dashboard
      </button>

      <div className="mb-8">
        <h2 className="text-2xl font-bold text-gray-900">Cast Your Vote</h2>
        <p className="text-gray-500">Choose from the list of nominated colleagues for this month.</p>
      </div>

      {error && (
        <div className="mb-6 p-4 bg-red-50 text-red-700 rounded-lg text-sm">
          {error}
        </div>
      )}

      {candidates.length === 0 ? (
        <div className="text-center py-12 bg-white rounded-xl border border-gray-200">
           <p className="text-gray-500">No candidates were nominated this month.</p>
        </div>
      ) : (
        <form onSubmit={handleSubmit} className="grid grid-cols-1 md:grid-cols-2 gap-4">
          {candidates.map(({ user: candidate, nominations }) => (
            <label 
              key={candidate.id} 
              className={`relative flex items-center p-4 border-2 rounded-xl cursor-pointer transition-all hover:shadow-md ${
                selectedCandidate === candidate.id 
                  ? 'border-purple-600 bg-purple-50' 
                  : 'border-gray-200 bg-white hover:border-purple-200'
              }`}
            >
              <input
                type="radio"
                name="candidate"
                value={candidate.id}
                checked={selectedCandidate === candidate.id}
                onChange={() => setSelectedCandidate(candidate.id)}
                className="sr-only"
              />
              <div className="flex-1">
                <div className="flex items-center justify-between">
                  <h3 className="font-bold text-gray-900">{candidate.name}</h3>
                  <span className="text-xs font-medium px-2 py-1 bg-gray-100 rounded-full text-gray-600">
                    {candidate.department}
                  </span>
                </div>
                <p className="text-sm text-gray-500 mt-1">
                  Received {nominations} nomination{nominations !== 1 ? 's' : ''}
                </p>
              </div>
              <div className={`ml-4 w-6 h-6 rounded-full border-2 flex items-center justify-center ${
                selectedCandidate === candidate.id
                  ? 'border-purple-600 bg-purple-600'
                  : 'border-gray-300'
              }`}>
                {selectedCandidate === candidate.id && <div className="w-2.5 h-2.5 rounded-full bg-white" />}
              </div>
            </label>
          ))}

          <div className="col-span-full mt-6 flex justify-end">
            <button
              type="submit"
              disabled={!selectedCandidate}
              className="px-8 py-3 bg-purple-600 text-white font-medium rounded-lg hover:bg-purple-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-purple-500 transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
            >
              Submit Vote
            </button>
          </div>
        </form>
      )}
    </div>
  );
};

import React, { useEffect, useState } from 'react';
import { mockDb } from '../services/mockDb';
import { Cycle, CycleStatus, CycleStats } from '../types';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer } from 'recharts';
import { Download, Plus, Play, StopCircle, Archive } from 'lucide-react';

const MONTHS = [
  'January', 'February', 'March', 'April', 'May', 'June',
  'July', 'August', 'September', 'October', 'November', 'December'
];

export const AdminDashboard: React.FC = () => {
  const [activeCycle, setActiveCycle] = useState<Cycle | undefined>();
  const [stats, setStats] = useState<CycleStats[]>([]);
  const [isCreating, setIsCreating] = useState(false);

  const refreshData = () => {
    const cycle = mockDb.getActiveCycle();
    setActiveCycle(cycle);
    if (cycle) {
      setStats(mockDb.getCycleStats(cycle.id));
    }
  };

  useEffect(() => {
    refreshData();
  }, []);

  const handleCreateCycle = () => {
    const now = new Date();
    mockDb.createCycle(now.getMonth(), now.getFullYear());
    setIsCreating(false);
    refreshData();
  };

  const updateStatus = (status: CycleStatus) => {
    if (activeCycle) {
      mockDb.updateCycleStatus(activeCycle.id, status);
      refreshData();
    }
  };

  const handleExport = () => {
    if (!activeCycle) return;

    // Convert stats to CSV
    const headers = ['Nominee Name', 'Department', 'Nominations', 'Votes'];
    const users = mockDb.getUsers();

    const rows = stats.map(s => {
      const u = users.find(user => user.id === s.nomineeId);
      return [
        s.nomineeName,
        u?.department || 'N/A',
        s.nominationCount,
        s.voteCount
      ].join(',');
    });

    const csvContent = "data:text/csv;charset=utf-8," + [headers.join(','), ...rows].join('\n');
    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", `results_${MONTHS[activeCycle.month]}_${activeCycle.year}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="space-y-8">
      {/* Header & Controls */}
      <div className="flex flex-col md:flex-row md:items-center md:justify-between gap-4">
        <div>
          <h1 className="text-2xl font-bold text-gray-900">Admin Dashboard</h1>
          <p className="text-gray-500">Manage voting cycles and view results.</p>
        </div>
        <div className="flex gap-2">
          <button 
            onClick={handleCreateCycle}
            className="flex items-center px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 text-sm font-medium"
          >
            <Plus className="w-4 h-4 mr-2" />
            New Cycle
          </button>
        </div>
      </div>

      {/* Cycle Management Card */}
      <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-6">
        <h2 className="text-lg font-bold text-gray-900 mb-4">Current Cycle Status</h2>

        {activeCycle ? (
          <div className="flex flex-col md:flex-row items-center justify-between bg-gray-50 p-4 rounded-lg">
            <div className="mb-4 md:mb-0">
              <span className="text-xl font-bold text-gray-800 mr-3">
                {MONTHS[activeCycle.month]} {activeCycle.year}
              </span>
              <span className={`px-3 py-1 rounded-full text-xs font-bold uppercase tracking-wide
                ${activeCycle.status === CycleStatus.NOMINATION ? 'bg-blue-200 text-blue-800' : 
                  activeCycle.status === CycleStatus.VOTING ? 'bg-green-200 text-green-800' : 
                  'bg-gray-200 text-gray-800'}`}>
                {activeCycle.status}
              </span>
            </div>

            <div className="flex gap-2">
              {activeCycle.status === CycleStatus.NOMINATION && (
                <button 
                  onClick={() => updateStatus(CycleStatus.VOTING)}
                  className="flex items-center px-3 py-2 bg-purple-100 text-purple-700 rounded hover:bg-purple-200 text-sm font-medium transition-colors"
                >
                  <Play className="w-4 h-4 mr-2" />
                  Start Voting
                </button>
              )}
              {activeCycle.status === CycleStatus.VOTING && (
                <button 
                  onClick={() => updateStatus(CycleStatus.CLOSED)}
                  className="flex items-center px-3 py-2 bg-red-100 text-red-700 rounded hover:bg-red-200 text-sm font-medium transition-colors"
                >
                  <StopCircle className="w-4 h-4 mr-2" />
                  Close Cycle
                </button>
              )}
              {activeCycle.status === CycleStatus.CLOSED && (
                <button disabled className="flex items-center px-3 py-2 bg-gray-200 text-gray-500 rounded cursor-not-allowed text-sm font-medium">
                  <Archive className="w-4 h-4 mr-2" />
                  Archived
                </button>
              )}
            </div>
          </div>
        ) : (
           <div className="text-center py-8 text-gray-500">No active cycle found. Create one to begin.</div>
        )}
      </div>

      {/* Results Visualization */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Chart */}
        <div className="lg:col-span-2 bg-white rounded-xl shadow-sm border border-gray-200 p-6">
          <div className="flex items-center justify-between mb-6">
            <h2 className="text-lg font-bold text-gray-900">Real-time Results</h2>
            <button 
              onClick={handleExport}
              disabled={stats.length === 0}
              className="flex items-center text-sm text-gray-600 hover:text-gray-900 disabled:opacity-50"
            >
              <Download className="w-4 h-4 mr-1" />
              CSV
            </button>
          </div>

          {stats.length > 0 ? (
            <div className="h-80 w-full">
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={stats} margin={{ top: 20, right: 30, left: 20, bottom: 5 }}>
                  <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f0f0f0" />
                  <XAxis dataKey="nomineeName" axisLine={false} tickLine={false} />
                  <YAxis axisLine={false} tickLine={false} allowDecimals={false} />
                  <Tooltip 
                    cursor={{ fill: '#f9fafb' }}
                    contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgba(0, 0, 0, 0.1)' }}
                  />
                  <Legend />
                  <Bar dataKey="nominationCount" name="Nominations" fill="#818cf8" radius={[4, 4, 0, 0]} />
                  <Bar dataKey="voteCount" name="Votes" fill="#4f46e5" radius={[4, 4, 0, 0]} />
                </BarChart>
              </ResponsiveContainer>
            </div>
          ) : (
            <div className="h-80 w-full flex items-center justify-center bg-gray-50 rounded-lg text-gray-400">
              No data available for this cycle yet.
            </div>
          )}
        </div>

        {/* Top Candidates List */}
        <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-6">
          <h2 className="text-lg font-bold text-gray-900 mb-4">Leaderboard</h2>
          <div className="space-y-4">
            {stats.length > 0 ? (
              stats.slice(0, 5).map((stat, index) => (
                <div key={stat.nomineeId} className="flex items-center p-3 hover:bg-gray-50 rounded-lg transition-colors">
                  <div className={`w-8 h-8 flex items-center justify-center rounded-full font-bold text-sm mr-3 ${
                    index === 0 ? 'bg-yellow-100 text-yellow-700' :
                    index === 1 ? 'bg-gray-100 text-gray-600' :
                    index === 2 ? 'bg-orange-100 text-orange-700' :
                    'bg-white border text-gray-500'
                  }`}>
                    {index + 1}
                  </div>
                  <div className="flex-1 min-w-0">
                    <p className="text-sm font-medium text-gray-900 truncate">{stat.nomineeName}</p>
                    <p className="text-xs text-gray-500">{stat.voteCount} votes</p>
                  </div>
                  <div className="text-xs font-semibold text-indigo-600 bg-indigo-50 px-2 py-1 rounded">
                    {Math.round((stat.voteCount / (stats.reduce((acc, curr) => acc + curr.voteCount, 0) || 1)) * 100)}%
                  </div>
                </div>
              ))
            ) : (
              <p className="text-sm text-gray-500">No votes cast yet.</p>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

import React from 'react';
import { Navigate, useLocation } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { UserRole } from '../types';

interface ProtectedRouteProps {
  children: React.ReactNode;
  allowedRoles?: UserRole[];
}

export const ProtectedRoute: React.FC<ProtectedRouteProps> = ({ children, allowedRoles }) => {
  const { user, isAuthenticated } = useAuth();
  const location = useLocation();

  if (!isAuthenticated || !user) {
    return <Navigate to="/login" state={{ from: location }} replace />;
  }

  if (allowedRoles && !allowedRoles.includes(user.role)) {
    return <Navigate to="/" replace />;
  }

  return <>{children}</>;
};

import React from 'react';
import { HashRouter, Routes, Route, Navigate } from 'react-router-dom';
import { AuthProvider } from './context/AuthContext';
import { Layout } from './components/Layout';
import { ProtectedRoute } from './components/ProtectedRoute';
import { Login } from './pages/Login';
import { Dashboard } from './pages/Dashboard';
import { AdminDashboard } from './pages/AdminDashboard';
import { Nominate } from './pages/Nominate';
import { Vote } from './pages/Vote';
import { UserRole } from './types';

function App() {
  return (
    <AuthProvider>
      <HashRouter>
        <Routes>
          <Route path="/login" element={<Login />} />

          <Route path="/" element={
            <ProtectedRoute>
              <Layout>
                <Dashboard />
              </Layout>
            </ProtectedRoute>
          } />

          <Route path="/nominate" element={
            <ProtectedRoute>
              <Layout>
                <Nominate />
              </Layout>
            </ProtectedRoute>
          } />

          <Route path="/vote" element={
            <ProtectedRoute>
              <Layout>
                <Vote />
              </Layout>
            </ProtectedRoute>
          } />

          <Route path="/admin" element={
            <ProtectedRoute allowedRoles={[UserRole.ADMIN]}>
              <Layout>
                <AdminDashboard />
              </Layout>
            </ProtectedRoute>
          } />

          <Route path="*" element={<Navigate to="/" replace />} />
        </Routes>
      </HashRouter>
    </AuthProvider>
  );
}

