  { id: 'u2', name: 'Jane Doe', email: 'jane@company.com', role: UserRole.EMPLOYEE, department: 'Engineering', status: 'ACTIVE' },
  { id: 'u3', name: 'John Smith', email: 'john@company.com', role: UserRole.EMPLOYEE, department: 'Marketing', status: 'ACTIVE' },
  { id: 'u4', name: 'Alice Johnson', email: 'alice@company.com', role: UserRole.EMPLOYEE, department: 'HR', status: 'ACTIVE' },
  { id: 'u5', name: 'Bob Williams', email: 'bob@company.com', role: UserRole.EMPLOYEE, department: 'Engineering', status: 'ACTIVE' },
  { id: 'u6', name: 'Charlie Brown', email: 'charlie@company.com', role: UserRole.EMPLOYEE, department: 'Sales', status: 'ACTIVE' },
];

const INITIAL_CYCLES: Cycle[] = [
  { id: 'c1', month: new Date().getMonth(), year: new Date().getFullYear(), status: CycleStatus.NOMINATION },
];

// Helper to access LocalStorage safely
const getStorage = <T,>(key: string, initial: T): T => {
  const stored = localStorage.getItem(key);
  if (!stored) {
    localStorage.setItem(key, JSON.stringify(initial));
    return initial;
  }
  return JSON.parse(stored);
};

const setStorage = <T,>(key: string, value: T): void => {
  localStorage.setItem(key, JSON.stringify(value));
};

// Database Service Simulation
export const mockDb = {
  getUsers: (): User[] => getStorage('users', INITIAL_USERS),

  getUserById: (id: string): User | undefined => {
    const users = getStorage<User[]>('users', INITIAL_USERS);
    return users.find(u => u.id === id);
  },

  getEmployees: (): User[] => {
    return getStorage<User[]>('users', INITIAL_USERS).filter(u => u.role === UserRole.EMPLOYEE);
  },

  updateUser: (user: User): void => {
    const users = getStorage<User[]>('users', INITIAL_USERS);
    const index = users.findIndex(u => u.id === user.id);
    if (index !== -1) {
      users[index] = user;
      setStorage('users', users);
    }
  },

  getCycles: (): Cycle[] => getStorage('cycles', INITIAL_CYCLES),

  getActiveCycle: (): Cycle | undefined => {
    const cycles = getStorage<Cycle[]>('cycles', INITIAL_CYCLES);
    // Find open cycle or most recent one
    return cycles.find(c => c.status !== CycleStatus.CLOSED) || cycles[cycles.length - 1];
  },

  createCycle: (month: number, year: number): Cycle => {
    const cycles = getStorage<Cycle[]>('cycles', INITIAL_CYCLES);
    // Deactivate previous active cycles
    const updatedCycles = cycles.map(c => 
      c.status !== CycleStatus.CLOSED ? { ...c, status: CycleStatus.CLOSED } : c
    );

    const newCycle: Cycle = {
      id: `c${Date.now()}`,
      month,
      year,
      status: CycleStatus.NOMINATION
    };

    updatedCycles.push(newCycle);
    setStorage('cycles', updatedCycles);
    return newCycle;
  },

  updateCycleStatus: (cycleId: string, status: CycleStatus): void => {
    const cycles = getStorage<Cycle[]>('cycles', INITIAL_CYCLES);
    const updated = cycles.map(c => c.id === cycleId ? { ...c, status } : c);
    setStorage('cycles', updated);
  },

  getNominations: (cycleId: string): Nomination[] => {
    const all = getStorage<Nomination[]>('nominations', []);
    return all.filter(n => n.cycleId === cycleId);
  },

  getUserNomination: (userId: string, cycleId: string): Nomination | undefined => {
    const all = getStorage<Nomination[]>('nominations', []);
    return all.find(n => n.nominatorId === userId && n.cycleId === cycleId);
  },

  addNomination: (nominatorId: string, nomineeId: string, cycleId: string, reason: string): void => {
    const all = getStorage<Nomination[]>('nominations', []);
    if (all.find(n => n.nominatorId === nominatorId && n.cycleId === cycleId)) {
      throw new Error("You have already nominated someone this cycle.");
    }
    const newNomination: Nomination = {
      id: `n${Date.now()}`,
      nominatorId,
      nomineeId,
      cycleId,
      reason,
      timestamp: Date.now()
    };
    all.push(newNomination);
    setStorage('nominations', all);
  },

  getVotes: (cycleId: string): Vote[] => {
    const all = getStorage<Vote[]>('votes', []);
    return all.filter(v => v.cycleId === cycleId);
  },

  getUserVote: (userId: string, cycleId: string): Vote | undefined => {
    const all = getStorage<Vote[]>('votes', []);
    return all.find(v => v.voterId === userId && v.cycleId === cycleId);
  },

  addVote: (voterId: string, nomineeId: string, cycleId: string): void => {
    const all = getStorage<Vote[]>('votes', []);
    if (all.find(v => v.voterId === voterId && v.cycleId === cycleId)) {
      throw new Error("You have already voted this cycle.");
    }
    const newVote: Vote = {
      id: `v${Date.now()}`,
      voterId,
      nomineeId,
      cycleId,
      timestamp: Date.now()
    };
    all.push(newVote);
    setStorage('votes', all);
  },

  getCycleStats: (cycleId: string): CycleStats[] => {
    const nominations = getStorage<Nomination[]>('nominations', []).filter(n => n.cycleId === cycleId);
    const votes = getStorage<Vote[]>('votes', []).filter(v => v.cycleId === cycleId);
    const employees = getStorage<User[]>('users', INITIAL_USERS);

    const statsMap = new Map<string, CycleStats>();

    // Initialize for all employees who received at least one nomination
    nominations.forEach(nom => {
      if (!statsMap.has(nom.nomineeId)) {
        const emp = employees.find(e => e.id === nom.nomineeId);
        if (emp) {
          statsMap.set(nom.nomineeId, {
            nomineeId: emp.id,
            nomineeName: emp.name,
            nominationCount: 0,
            voteCount: 0
          });
        }
      }
      const stat = statsMap.get(nom.nomineeId);
      if (stat) stat.nominationCount++;
    });

    // Count votes
    votes.forEach(vote => {
       // Only count votes if the person was nominated (optional rule, but good for structure)
       // Or simply count all votes. Let's count all votes but ensure they map to a user
       if (!statsMap.has(vote.nomineeId)) {
         const emp = employees.find(e => e.id === vote.nomineeId);
         if (emp) {
            statsMap.set(vote.nomineeId, {
              nomineeId: emp.id,
              nomineeName: emp.name,
              nominationCount: 0,
              voteCount: 0
            });
         }
       }
       const stat = statsMap.get(vote.nomineeId);
       if (stat) stat.voteCount++;
    });

    return Array.from(statsMap.values()).sort((a, b) => b.voteCount - a.voteCount);
  }
};

import React, { useEffect, useState } from 'react';
import { mockDb } from '../services/mockDb';
import { Cycle, CycleStatus, CycleStats, User, UserRole } from '../types';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer } from 'recharts';
import { Download, Plus, Play, StopCircle, Archive, Pencil, Power, X } from 'lucide-react';

const MONTHS = [
  'January', 'February', 'March', 'April', 'May', 'June',
  'July', 'August', 'September', 'October', 'November', 'December'
];

export const AdminDashboard: React.FC = () => {
  const [activeCycle, setActiveCycle] = useState<Cycle | undefined>();
  const [stats, setStats] = useState<CycleStats[]>([]);
  const [isCreating, setIsCreating] = useState(false);

  // Employee Management State
  const [users, setUsers] = useState<User[]>([]);
  const [isEditModalOpen, setIsEditModalOpen] = useState(false);
  const [editingUser, setEditingUser] = useState<User | null>(null);

  const refreshData = () => {
    const cycle = mockDb.getActiveCycle();
    setActiveCycle(cycle);
    if (cycle) {
      setStats(mockDb.getCycleStats(cycle.id));
    }
    setUsers(mockDb.getUsers());
  };

  useEffect(() => {
    refreshData();
  }, []);

  const handleCreateCycle = () => {
    const now = new Date();
    mockDb.createCycle(now.getMonth(), now.getFullYear());
    setIsCreating(false);
    refreshData();
  };

  const updateStatus = (status: CycleStatus) => {
    if (activeCycle) {
      mockDb.updateCycleStatus(activeCycle.id, status);
      refreshData();
    }
  };

  const handleExport = () => {
    if (!activeCycle) return;

    // Convert stats to CSV
    const headers = ['Nominee Name', 'Department', 'Nominations', 'Votes'];
    const users = mockDb.getUsers();

    const rows = stats.map(s => {
      const u = users.find(user => user.id === s.nomineeId);
      return [
        s.nomineeName,
        u?.department || 'N/A',
        s.nominationCount,
        s.voteCount
      ].join(',');
    });

    const csvContent = "data:text/csv;charset=utf-8," + [headers.join(','), ...rows].join('\n');
    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", `results_${MONTHS[activeCycle.month]}_${activeCycle.year}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  // User Management Functions
  const handleEditClick = (user: User) => {
    setEditingUser({ ...user });
    setIsEditModalOpen(true);
  };

  const handleUserUpdate = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingUser) {
      mockDb.updateUser(editingUser);
      setIsEditModalOpen(false);
      setEditingUser(null);
      refreshData();
    }
  };

  const toggleUserStatus = (user: User) => {
    const newStatus = user.status === 'ACTIVE' ? 'INACTIVE' : 'ACTIVE';
    mockDb.updateUser({ ...user, status: newStatus });
    refreshData();
  };

  return (
    <div className="space-y-8 pb-10">
      {/* Header & Controls */}
      <div className="flex flex-col md:flex-row md:items-center md:justify-between gap-4">
        <div>
          <h1 className="text-2xl font-bold text-gray-900">Admin Dashboard</h1>
          <p className="text-gray-500">Manage voting cycles, view results, and manage employees.</p>
        </div>
        <div className="flex gap-2">
          <button 
            onClick={handleCreateCycle}
            className="flex items-center px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 text-sm font-medium"
          >
            <Plus className="w-4 h-4 mr-2" />
            New Cycle
          </button>
        </div>
      </div>

      {/* Cycle Management Card */}
      <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-6">
        <h2 className="text-lg font-bold text-gray-900 mb-4">Current Cycle Status</h2>

        {activeCycle ? (
          <div className="flex flex-col md:flex-row items-center justify-between bg-gray-50 p-4 rounded-lg">
            <div className="mb-4 md:mb-0">
              <span className="text-xl font-bold text-gray-800 mr-3">
                {MONTHS[activeCycle.month]} {activeCycle.year}
              </span>
              <span className={`px-3 py-1 rounded-full text-xs font-bold uppercase tracking-wide
                ${activeCycle.status === CycleStatus.NOMINATION ? 'bg-blue-200 text-blue-800' : 
                  activeCycle.status === CycleStatus.VOTING ? 'bg-green-200 text-green-800' : 
                  'bg-gray-200 text-gray-800'}`}>
                {activeCycle.status}
              </span>
            </div>

            <div className="flex gap-2">
              {activeCycle.status === CycleStatus.NOMINATION && (
                <button 
                  onClick={() => updateStatus(CycleStatus.VOTING)}
                  className="flex items-center px-3 py-2 bg-purple-100 text-purple-700 rounded hover:bg-purple-200 text-sm font-medium transition-colors"
                >
                  <Play className="w-4 h-4 mr-2" />
                  Start Voting
                </button>
              )}
              {activeCycle.status === CycleStatus.VOTING && (
                <button 
                  onClick={() => updateStatus(CycleStatus.CLOSED)}
                  className="flex items-center px-3 py-2 bg-red-100 text-red-700 rounded hover:bg-red-200 text-sm font-medium transition-colors"
                >
                  <StopCircle className="w-4 h-4 mr-2" />
                  Close Cycle
                </button>
              )}
              {activeCycle.status === CycleStatus.CLOSED && (
                <button disabled className="flex items-center px-3 py-2 bg-gray-200 text-gray-500 rounded cursor-not-allowed text-sm font-medium">
                  <Archive className="w-4 h-4 mr-2" />
                  Archived
                </button>
              )}
            </div>
          </div>
        ) : (
           <div className="text-center py-8 text-gray-500">No active cycle found. Create one to begin.</div>
        )}
      </div>

      {/* Results Visualization */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Chart */}
        <div className="lg:col-span-2 bg-white rounded-xl shadow-sm border border-gray-200 p-6">
          <div className="flex items-center justify-between mb-6">
            <h2 className="text-lg font-bold text-gray-900">Real-time Results</h2>
            <button 
              onClick={handleExport}
              disabled={stats.length === 0}
              className="flex items-center text-sm text-gray-600 hover:text-gray-900 disabled:opacity-50"
            >
              <Download className="w-4 h-4 mr-1" />
              CSV
            </button>
          </div>

          {stats.length > 0 ? (
            <div className="h-80 w-full">
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={stats} margin={{ top: 20, right: 30, left: 20, bottom: 5 }}>
                  <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f0f0f0" />
                  <XAxis dataKey="nomineeName" axisLine={false} tickLine={false} />
                  <YAxis axisLine={false} tickLine={false} allowDecimals={false} />
                  <Tooltip 
                    cursor={{ fill: '#f9fafb' }}
                    contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgba(0, 0, 0, 0.1)' }}
                  />
                  <Legend />
                  <Bar dataKey="nominationCount" name="Nominations" fill="#818cf8" radius={[4, 4, 0, 0]} />
                  <Bar dataKey="voteCount" name="Votes" fill="#4f46e5" radius={[4, 4, 0, 0]} />
                </BarChart>
              </ResponsiveContainer>
            </div>
          ) : (
            <div className="h-80 w-full flex items-center justify-center bg-gray-50 rounded-lg text-gray-400">
              No data available for this cycle yet.
            </div>
          )}
        </div>

        {/* Top Candidates List */}
        <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-6">
          <h2 className="text-lg font-bold text-gray-900 mb-4">Leaderboard</h2>
          <div className="space-y-4">
            {stats.length > 0 ? (
              stats.slice(0, 5).map((stat, index) => (
                <div key={stat.nomineeId} className="flex items-center p-3 hover:bg-gray-50 rounded-lg transition-colors">
                  <div className={`w-8 h-8 flex items-center justify-center rounded-full font-bold text-sm mr-3 ${
                    index === 0 ? 'bg-yellow-100 text-yellow-700' :
                    index === 1 ? 'bg-gray-100 text-gray-600' :
                    index === 2 ? 'bg-orange-100 text-orange-700' :
                    'bg-white border text-gray-500'
                  }`}>
                    {index + 1}
                  </div>
                  <div className="flex-1 min-w-0">
                    <p className="text-sm font-medium text-gray-900 truncate">{stat.nomineeName}</p>
                    <p className="text-xs text-gray-500">{stat.voteCount} votes</p>
                  </div>
                  <div className="text-xs font-semibold text-indigo-600 bg-indigo-50 px-2 py-1 rounded">
                    {Math.round((stat.voteCount / (stats.reduce((acc, curr) => acc + curr.voteCount, 0) || 1)) * 100)}%
                  </div>
                </div>
              ))
            ) : (
              <p className="text-sm text-gray-500">No votes cast yet.</p>
            )}
          </div>
        </div>
      </div>

      {/* Employee Directory Section */}
      <div className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden">
        <div className="p-6 border-b border-gray-200">
          <h2 className="text-lg font-bold text-gray-900">Employee Directory</h2>
          <p className="text-sm text-gray-500 mt-1">Manage user accounts and access.</p>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-sm text-left">
            <thead className="bg-gray-50 text-gray-500 font-medium border-b border-gray-200">
              <tr>
                <th className="px-6 py-3">Name</th>
                <th className="px-6 py-3">Email</th>
                <th className="px-6 py-3">Department</th>
                <th className="px-6 py-3">Role</th>
                <th className="px-6 py-3">Status</th>
                <th className="px-6 py-3 text-right">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-100">
              {users.map(user => (
                <tr key={user.id} className="hover:bg-gray-50 transition-colors">
                  <td className="px-6 py-3 font-medium text-gray-900">{user.name}</td>
                  <td className="px-6 py-3 text-gray-500">{user.email}</td>
                  <td className="px-6 py-3 text-gray-500">{user.department}</td>
                  <td className="px-6 py-3">
                    <span className={`inline-flex items-center px-2 py-0.5 rounded text-xs font-medium ${
                      user.role === UserRole.ADMIN ? 'bg-purple-100 text-purple-800' : 'bg-blue-100 text-blue-800'
                    }`}>
                      {user.role}
                    </span>
                  </td>
                  <td className="px-6 py-3">
                     <span className={`inline-flex items-center px-2 py-0.5 rounded text-xs font-medium ${
                      user.status === 'ACTIVE' ? 'bg-green-100 text-green-800' : 'bg-gray-100 text-gray-600'
                    }`}>
                      {user.status}
                    </span>
                  </td>
                  <td className="px-6 py-3 text-right space-x-2">
                    <button 
                      onClick={() => handleEditClick(user)}
                      className="p-1 text-gray-500 hover:text-indigo-600 transition-colors"
                      title="Edit Employee"
                    >
                      <Pencil className="w-4 h-4" />
                    </button>
                    <button 
                      onClick={() => toggleUserStatus(user)}
                      className={`p-1 transition-colors ${
                        user.status === 'ACTIVE' 
                          ? 'text-gray-500 hover:text-red-600' 
                          : 'text-red-600 hover:text-green-600'
                      }`}
                      title={user.status === 'ACTIVE' ? "Deactivate Employee" : "Activate Employee"}
                    >
                      <Power className="w-4 h-4" />
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {/* Edit User Modal */}
      {isEditModalOpen && editingUser && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50">
          <div className="bg-white rounded-xl shadow-xl max-w-md w-full mx-4 overflow-hidden animate-in fade-in zoom-in duration-200">
            <div className="flex items-center justify-between p-4 border-b border-gray-200">
              <h3 className="font-bold text-gray-900">Edit Employee</h3>
              <button 
                onClick={() => setIsEditModalOpen(false)}
                className="text-gray-400 hover:text-gray-600"
              >
                <X className="w-5 h-5" />
              </button>
            </div>

            <form onSubmit={handleUserUpdate} className="p-4 space-y-4">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Full Name</label>
                <input
                  type="text"
                  required
                  value={editingUser.name}
                  onChange={e => setEditingUser({ ...editingUser, name: e.target.value })}
                  className="w-full rounded-lg border-gray-300 shadow-sm focus:border-indigo-500 focus:ring-indigo-500"
                />
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Department</label>
                <input
                  type="text"
                  required
                  value={editingUser.department}
                  onChange={e => setEditingUser({ ...editingUser, department: e.target.value })}
                  className="w-full rounded-lg border-gray-300 shadow-sm focus:border-indigo-500 focus:ring-indigo-500"
                />
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Email</label>
                <input
                  type="email"
                  required
                  disabled
                  value={editingUser.email}
                  className="w-full rounded-lg border-gray-200 bg-gray-50 text-gray-500 cursor-not-allowed"
                />
                <p className="text-xs text-gray-400 mt-1">Email cannot be changed.</p>
              </div>

              <div className="pt-2 flex justify-end gap-3">
                <button
                  type="button"
                  onClick={() => setIsEditModalOpen(false)}
                  className="px-4 py-2 text-sm font-medium text-gray-700 bg-white border border-gray-300 rounded-lg hover:bg-gray-50"
                >
                  Cancel
                </button>
                <button
                  type="submit"
                  className="px-4 py-2 text-sm font-medium text-white bg-indigo-600 rounded-lg hover:bg-indigo-700"
                >
                  Save Changes
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

import { User, UserRole, Cycle, CycleStatus, Nomination, Vote, CycleStats } from '../types';

// Initial Mock Data
const INITIAL_USERS: User[] = [
  { id: 'u1', name: 'Admin User', email: 'admin@company.com', role: UserRole.ADMIN, department: 'Management', status: 'ACTIVE' },
  { id: 'u2', name: 'Jane Doe', email: 'jane@company.com', role: UserRole.EMPLOYEE, department: 'Engineering', status: 'ACTIVE' },
  { id: 'u3', name: 'John Smith', email: 'john@company.com', role: UserRole.EMPLOYEE, department: 'Marketing', status: 'ACTIVE' },
  { id: 'u4', name: 'Alice Johnson', email: 'alice@company.com', role: UserRole.EMPLOYEE, department: 'HR', status: 'ACTIVE' },
  { id: 'u5', name: 'Bob Williams', email: 'bob@company.com', role: UserRole.EMPLOYEE, department: 'Engineering', status: 'ACTIVE' },
  { id: 'u6', name: 'Charlie Brown', email: 'charlie@company.com', role: UserRole.EMPLOYEE, department: 'Sales', status: 'ACTIVE' },
];

const INITIAL_CYCLES: Cycle[] = [
  { id: 'c1', month: new Date().getMonth(), year: new Date().getFullYear(), status: CycleStatus.NOMINATION },
];

// Helper to access LocalStorage safely
const getStorage = <T,>(key: string, initial: T): T => {
  const stored = localStorage.getItem(key);
  if (!stored) {
    localStorage.setItem(key, JSON.stringify(initial));
    return initial;
  }
  return JSON.parse(stored);
};

const setStorage = <T,>(key: string, value: T): void => {
  localStorage.setItem(key, JSON.stringify(value));
};

// Database Service Simulation
export const mockDb = {
  getUsers: (): User[] => getStorage('users', INITIAL_USERS),

  getUserById: (id: string): User | undefined => {
    const users = getStorage<User[]>('users', INITIAL_USERS);
    return users.find(u => u.id === id);
  },

  getEmployees: (): User[] => {
    return getStorage<User[]>('users', INITIAL_USERS).filter(u => u.role === UserRole.EMPLOYEE);
  },

  addUser: (user: Omit<User, 'id' | 'status'>): void => {
    const users = getStorage<User[]>('users', INITIAL_USERS);
    if (users.find(u => u.email === user.email)) {
      throw new Error("User with this email already exists");
    }
    const newUser: User = {
      ...user,
      id: `u${Date.now()}`,
      status: 'ACTIVE'
    };
    users.push(newUser);
    setStorage('users', users);
  },

  updateUser: (user: User): void => {
    const users = getStorage<User[]>('users', INITIAL_USERS);
    const index = users.findIndex(u => u.id === user.id);
    if (index !== -1) {
      users[index] = user;
      setStorage('users', users);
    }
  },

  getCycles: (): Cycle[] => getStorage('cycles', INITIAL_CYCLES),

  getActiveCycle: (): Cycle | undefined => {
    const cycles = getStorage<Cycle[]>('cycles', INITIAL_CYCLES);
    // Find open cycle or most recent one
    return cycles.find(c => c.status !== CycleStatus.CLOSED) || cycles[cycles.length - 1];
  },

  createCycle: (month: number, year: number): Cycle => {
    const cycles = getStorage<Cycle[]>('cycles', INITIAL_CYCLES);
    // Deactivate previous active cycles
    const updatedCycles = cycles.map(c => 
      c.status !== CycleStatus.CLOSED ? { ...c, status: CycleStatus.CLOSED } : c
    );

    const newCycle: Cycle = {
      id: `c${Date.now()}`,
      month,
      year,
      status: CycleStatus.NOMINATION
    };

    updatedCycles.push(newCycle);
    setStorage('cycles', updatedCycles);
    return newCycle;
  },

  updateCycleStatus: (cycleId: string, status: CycleStatus): void => {
    const cycles = getStorage<Cycle[]>('cycles', INITIAL_CYCLES);
    const updated = cycles.map(c => c.id === cycleId ? { ...c, status } : c);
    setStorage('cycles', updated);
  },

  getNominations: (cycleId: string): Nomination[] => {
    const all = getStorage<Nomination[]>('nominations', []);
    return all.filter(n => n.cycleId === cycleId);
  },

  getUserNomination: (userId: string, cycleId: string): Nomination | undefined => {
    const all = getStorage<Nomination[]>('nominations', []);
    return all.find(n => n.nominatorId === userId && n.cycleId === cycleId);
  },

  addNomination: (nominatorId: string, nomineeId: string, cycleId: string, reason: string): void => {
    const all = getStorage<Nomination[]>('nominations', []);
    if (all.find(n => n.nominatorId === nominatorId && n.cycleId === cycleId)) {
      throw new Error("You have already nominated someone this cycle.");
    }
    const newNomination: Nomination = {
      id: `n${Date.now()}`,
      nominatorId,
      nomineeId,
      cycleId,
      reason,
      timestamp: Date.now()
    };
    all.push(newNomination);
    setStorage('nominations', all);
  },

  getVotes: (cycleId: string): Vote[] => {
    const all = getStorage<Vote[]>('votes', []);
    return all.filter(v => v.cycleId === cycleId);
  },

  getUserVote: (userId: string, cycleId: string): Vote | undefined => {
    const all = getStorage<Vote[]>('votes', []);
    return all.find(v => v.voterId === userId && v.cycleId === cycleId);
  },

  addVote: (voterId: string, nomineeId: string, cycleId: string): void => {
    const all = getStorage<Vote[]>('votes', []);
    if (all.find(v => v.voterId === voterId && v.cycleId === cycleId)) {
      throw new Error("You have already voted this cycle.");
    }
    const newVote: Vote = {
      id: `v${Date.now()}`,
      voterId,
      nomineeId,
      cycleId,
      timestamp: Date.now()
    };
    all.push(newVote);
    setStorage('votes', all);
  },

  getCycleStats: (cycleId: string): CycleStats[] => {
    const nominations = getStorage<Nomination[]>('nominations', []).filter(n => n.cycleId === cycleId);
    const votes = getStorage<Vote[]>('votes', []).filter(v => v.cycleId === cycleId);
    const employees = getStorage<User[]>('users', INITIAL_USERS);

    const statsMap = new Map<string, CycleStats>();

    // Initialize for all employees who received at least one nomination
    nominations.forEach(nom => {
      if (!statsMap.has(nom.nomineeId)) {
        const emp = employees.find(e => e.id === nom.nomineeId);
        if (emp) {
          statsMap.set(nom.nomineeId, {
            nomineeId: emp.id,
            nomineeName: emp.name,
            nominationCount: 0,
            voteCount: 0
          });
        }
      }
      const stat = statsMap.get(nom.nomineeId);
      if (stat) stat.nominationCount++;
    });

    // Count votes
    votes.forEach(vote => {
       // Only count votes if the person was nominated (optional rule, but good for structure)
       // Or simply count all votes. Let's count all votes but ensure they map to a user
       if (!statsMap.has(vote.nomineeId)) {
         const emp = employees.find(e => e.id === vote.nomineeId);
         if (emp) {
            statsMap.set(vote.nomineeId, {
              nomineeId: emp.id,
              nomineeName: emp.name,
              nominationCount: 0,
              voteCount: 0
            });
         }
       }
       const stat = statsMap.get(vote.nomineeId);
       if (stat) stat.voteCount++;
    });

    return Array.from(statsMap.values()).sort((a, b) => b.voteCount - a.voteCount);
  }
};

import React, { useEffect, useState } from 'react';
import { mockDb } from '../services/mockDb';
import { Cycle, CycleStatus, CycleStats, User, UserRole } from '../types';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer } from 'recharts';
import { Download, Plus, Play, StopCircle, Archive, Pencil, Power, X, UserPlus } from 'lucide-react';

const MONTHS = [
  'January', 'February', 'March', 'April', 'May', 'June',
  'July', 'August', 'September', 'October', 'November', 'December'
];

export const AdminDashboard: React.FC = () => {
  const [activeCycle, setActiveCycle] = useState<Cycle | undefined>();
  const [stats, setStats] = useState<CycleStats[]>([]);
  const [isCreating, setIsCreating] = useState(false);

  // Employee Management State
  const [users, setUsers] = useState<User[]>([]);
  const [isEditModalOpen, setIsEditModalOpen] = useState(false);
  const [editingUser, setEditingUser] = useState<User | null>(null);

  // Add Employee Modal State
  const [isAddUserModalOpen, setIsAddUserModalOpen] = useState(false);
  const [newUser, setNewUser] = useState({
    name: '',
    email: '',
    department: '',
    role: UserRole.EMPLOYEE
  });
  const [addUserError, setAddUserError] = useState('');

  const refreshData = () => {
    const cycle = mockDb.getActiveCycle();
    setActiveCycle(cycle);
    if (cycle) {
      setStats(mockDb.getCycleStats(cycle.id));
    }
    setUsers(mockDb.getUsers());
  };

  useEffect(() => {
    refreshData();
  }, []);

  const handleCreateCycle = () => {
    const now = new Date();
    mockDb.createCycle(now.getMonth(), now.getFullYear());
    setIsCreating(false);
    refreshData();
  };

  const updateStatus = (status: CycleStatus) => {
    if (activeCycle) {
      mockDb.updateCycleStatus(activeCycle.id, status);
      refreshData();
    }
  };

  const handleExport = () => {
    if (!activeCycle) return;

    // Convert stats to CSV
    const headers = ['Nominee Name', 'Department', 'Nominations', 'Votes'];
    const users = mockDb.getUsers();

    const rows = stats.map(s => {
      const u = users.find(user => user.id === s.nomineeId);
      return [
        s.nomineeName,
        u?.department || 'N/A',
        s.nominationCount,
        s.voteCount
      ].join(',');
    });

    const csvContent = "data:text/csv;charset=utf-8," + [headers.join(','), ...rows].join('\n');
    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", `results_${MONTHS[activeCycle.month]}_${activeCycle.year}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  // User Management Functions
  const handleEditClick = (user: User) => {
    setEditingUser({ ...user });
    setIsEditModalOpen(true);
  };

  const handleUserUpdate = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingUser) {
      mockDb.updateUser(editingUser);
      setIsEditModalOpen(false);
      setEditingUser(null);
      refreshData();
    }
  };

  const toggleUserStatus = (user: User) => {
    const newStatus = user.status === 'ACTIVE' ? 'INACTIVE' : 'ACTIVE';
    mockDb.updateUser({ ...user, status: newStatus });
    refreshData();
  };

  const handleAddUserSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setAddUserError('');
    try {
      mockDb.addUser({
        name: newUser.name,
        email: newUser.email,
        department: newUser.department,
        role: newUser.role
      });
      setIsAddUserModalOpen(false);
      setNewUser({
        name: '',
        email: '',
        department: '',
        role: UserRole.EMPLOYEE
      });
      refreshData();
