import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { mockDb } from '../services/mockDb';
import { Cycle, CycleStatus, User } from '../types';
import { ArrowLeft, Send } from 'lucide-react';

export const Nominate: React.FC = () => {
  const navigate = useNavigate();
  const { user } = useAuth();
  const [activeCycle, setActiveCycle] = useState<Cycle | undefined>();
  const [employees, setEmployees] = useState<User[]>([]);
  const [selectedNominee, setSelectedNominee] = useState('');
  const [reason, setReason] = useState('');
  const [error, setError] = useState('');
  const [success, setSuccess] = useState(false);

  useEffect(() => {
    const cycle = mockDb.getActiveCycle();
    setActiveCycle(cycle);

    // Filter out current user from potential nominees
    const allEmployees = mockDb.getEmployees().filter(e => e.id !== user?.id);
    setEmployees(allEmployees);

    // Check if already nominated
    if (user && cycle) {
      const existing = mockDb.getUserNomination(user.id, cycle.id);
      if (existing) {
        setSuccess(true);
      }
    }
  }, [user]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!activeCycle || !user) return;

    try {
      mockDb.addNomination(user.id, selectedNominee, activeCycle.id, reason);
      setSuccess(true);
      setTimeout(() => navigate('/'), 2000);
    } catch (err: any) {
      setError(err.message);
    }
  };

  if (!activeCycle || activeCycle.status !== CycleStatus.NOMINATION) {
    return (
      <div className="text-center py-16">
        <div className="w-16 h-16 bg-gray-100 rounded-full flex items-center justify-center mx-auto mb-4">
          <Send className="w-8 h-8 text-gray-400" />
        </div>
        <h2 className="text-xl font-bold text-gray-900">Nominations Closed</h2>
        <p className="text-gray-500 mt-2">The nomination phase is currently inactive.</p>
        <button onClick={() => navigate('/')} className="mt-6 text-indigo-600 hover:text-indigo-800 font-medium hover:underline">
          Return to Dashboard
        </button>
      </div>
    );
  }

  if (success) {
    return (
      <div className="max-w-xl mx-auto text-center py-16 animate-in fade-in zoom-in duration-300">
        <div className="w-20 h-20 bg-green-100 text-green-600 rounded-full flex items-center justify-center mx-auto mb-6 shadow-sm">
          <Send className="w-10 h-10" />
        </div>
        <h2 className="text-3xl font-bold text-gray-900 tracking-tight">Nomination Submitted!</h2>
        <p className="text-gray-600 mt-3 text-lg">Thank you for recognizing your colleague's hard work.</p>
        <p className="text-gray-400 text-sm mt-8 animate-pulse">Redirecting to dashboard...</p>
      </div>
    );
  }

  return (
    <div className="max-w-2xl mx-auto">
      <button 
        onClick={() => navigate('/')}
        className="flex items-center text-gray-500 hover:text-gray-900 mb-8 transition-colors group"
      >
        <ArrowLeft className="w-4 h-4 mr-2 group-hover:-translate-x-1 transition-transform" />
        Back to Dashboard
      </button>

      <div className="bg-white rounded-2xl shadow-sm border border-gray-200 overflow-hidden">
        <div className="p-8 border-b border-gray-100 bg-gray-50/50">
          <h2 className="text-2xl font-bold text-gray-900">Nominate a Colleague</h2>
          <p className="text-gray-500 mt-2">Select an employee and share why they deserve to be Employee of the Month.</p>
        </div>

        <form onSubmit={handleSubmit} className="p-8 space-y-6">
          <div>
            <label className="block text-sm font-semibold text-gray-700 mb-2">Select Nominee</label>
            <div className="relative">
              <select
                required
                value={selectedNominee}
                onChange={(e) => setSelectedNominee(e.target.value)}
                className="w-full px-4 py-3 rounded-xl border border-gray-300 shadow-sm focus:border-indigo-500 focus:ring-2 focus:ring-indigo-200 focus:outline-none bg-white text-gray-900 appearance-none transition-all cursor-pointer"
              >
                <option value="">-- Choose an employee --</option>
                {employees.map(emp => (
                  <option key={emp.id} value={emp.id}>
                    {emp.name} — {emp.department}
                  </option>
                ))}
              </select>
              <div className="absolute inset-y-0 right-0 flex items-center px-4 pointer-events-none text-gray-500">
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 9l-7 7-7-7"></path></svg>
              </div>
            </div>
          </div>

          <div>
            <label className="block text-sm font-semibold text-gray-700 mb-2">Reason for Nomination</label>
            <textarea
              required
              value={reason}
              onChange={(e) => setReason(e.target.value)}
              rows={5}
              className="w-full px-4 py-3 rounded-xl border border-gray-300 shadow-sm focus:border-indigo-500 focus:ring-2 focus:ring-indigo-200 focus:outline-none bg-white text-gray-900 placeholder-gray-400 transition-all resize-none"
              placeholder="Describe their achievements, attitude, or specific contributions that make them stand out..."
            ></textarea>
            <p className="mt-2 text-xs text-gray-500 flex items-center">
              <span className="w-1.5 h-1.5 bg-gray-400 rounded-full mr-1.5"></span>
              Your nomination is anonymous to the nominee, but visible to admins.
            </p>
          </div>

          {error && (
            <div className="p-4 bg-red-50 text-red-700 rounded-xl text-sm border border-red-100 flex items-center">
              <span className="w-1.5 h-1.5 bg-red-500 rounded-full mr-2"></span>
              {error}
            </div>
          )}

          <div className="flex justify-end pt-4">
            <button
              type="submit"
              className="px-8 py-3 bg-indigo-600 text-white font-semibold rounded-xl hover:bg-indigo-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-indigo-500 transition-all shadow-sm hover:shadow active:scale-[0.99]"
            >
              Submit Nomination
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

import React, { useEffect, useState } from 'react';
import { mockDb } from '../services/mockDb';
import { Cycle, CycleStatus, CycleStats, User, UserRole } from '../types';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer } from 'recharts';
import { Download, Plus, Play, StopCircle, Archive, Pencil, Power, X, UserPlus, Search } from 'lucide-react';

const MONTHS = [
  'January', 'February', 'March', 'April', 'May', 'June',
  'July', 'August', 'September', 'October', 'November', 'December'
];

export const AdminDashboard: React.FC = () => {
  const [activeCycle, setActiveCycle] = useState<Cycle | undefined>();
  const [stats, setStats] = useState<CycleStats[]>([]);
  const [isCreating, setIsCreating] = useState(false);

  // Employee Management State
  const [users, setUsers] = useState<User[]>([]);
  const [isEditModalOpen, setIsEditModalOpen] = useState(false);
  const [editingUser, setEditingUser] = useState<User | null>(null);

  // Add Employee Modal State
  const [isAddUserModalOpen, setIsAddUserModalOpen] = useState(false);
  const [newUser, setNewUser] = useState({
    name: '',
    email: '',
    department: '',
    role: UserRole.EMPLOYEE
  });
  const [addUserError, setAddUserError] = useState('');

  const refreshData = () => {
    const cycle = mockDb.getActiveCycle();
    setActiveCycle(cycle);
    if (cycle) {
      setStats(mockDb.getCycleStats(cycle.id));
    }
    setUsers(mockDb.getUsers());
  };

  useEffect(() => {
    refreshData();
  }, []);

  const handleCreateCycle = () => {
    const now = new Date();
    mockDb.createCycle(now.getMonth(), now.getFullYear());
    setIsCreating(false);
    refreshData();
  };

  const updateStatus = (status: CycleStatus) => {
    if (activeCycle) {
      mockDb.updateCycleStatus(activeCycle.id, status);
      refreshData();
    }
  };

  const handleExport = () => {
    if (!activeCycle) return;

    // Convert stats to CSV
    const headers = ['Nominee Name', 'Department', 'Nominations', 'Votes'];
    const users = mockDb.getUsers();

    const rows = stats.map(s => {
      const u = users.find(user => user.id === s.nomineeId);
      return [
        s.nomineeName,
        u?.department || 'N/A',
        s.nominationCount,
        s.voteCount
      ].join(',');
    });

    const csvContent = "data:text/csv;charset=utf-8," + [headers.join(','), ...rows].join('\n');
    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", `results_${MONTHS[activeCycle.month]}_${activeCycle.year}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  // User Management Functions
  const handleEditClick = (user: User) => {
    setEditingUser({ ...user });
    setIsEditModalOpen(true);
  };

  const handleUserUpdate = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingUser) {
      mockDb.updateUser(editingUser);
      setIsEditModalOpen(false);
      setEditingUser(null);
      refreshData();
    }
  };

  const toggleUserStatus = (user: User) => {
    const newStatus = user.status === 'ACTIVE' ? 'INACTIVE' : 'ACTIVE';
    mockDb.updateUser({ ...user, status: newStatus });
    refreshData();
  };

  const handleAddUserSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setAddUserError('');
    try {
      mockDb.addUser({
        name: newUser.name,
        email: newUser.email,
        department: newUser.department,
        role: newUser.role
      });
      setIsAddUserModalOpen(false);
      setNewUser({
        name: '',
        email: '',
        department: '',
        role: UserRole.EMPLOYEE
      });
      refreshData();
    } catch (err: any) {
      setAddUserError(err.message);
    }
  };

  return (
    <div className="space-y-8 pb-10">
      {/* Header & Controls */}
      <div className="flex flex-col md:flex-row md:items-center md:justify-between gap-4">
        <div>
          <h1 className="text-2xl font-bold text-gray-900 tracking-tight">Admin Dashboard</h1>
          <p className="text-gray-500 mt-1">Manage voting cycles, view results, and manage employees.</p>
        </div>
        <div className="flex gap-2">
          <button 
            onClick={handleCreateCycle}
            className="flex items-center px-5 py-2.5 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 text-sm font-semibold shadow-sm transition-all active:scale-95"
          >
            <Plus className="w-4 h-4 mr-2" />
            New Cycle
          </button>
        </div>
      </div>

      {/* Cycle Management Card */}
      <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-6">
        <h2 className="text-lg font-bold text-gray-900 mb-4">Current Cycle Status</h2>

        {activeCycle ? (
          <div className="flex flex-col md:flex-row items-center justify-between bg-gray-50 p-5 rounded-xl border border-gray-100">
            <div className="mb-4 md:mb-0">
              <span className="text-xl font-bold text-gray-900 mr-3">
                {MONTHS[activeCycle.month]} {activeCycle.year}
              </span>
              <span className={`px-3 py-1 rounded-full text-xs font-bold uppercase tracking-wide
                ${activeCycle.status === CycleStatus.NOMINATION ? 'bg-blue-100 text-blue-800' : 
                  activeCycle.status === CycleStatus.VOTING ? 'bg-green-100 text-green-800' : 
                  'bg-gray-100 text-gray-800'}`}>
                {activeCycle.status}
              </span>
            </div>

            <div className="flex gap-3">
              {activeCycle.status === CycleStatus.NOMINATION && (
                <button 
                  onClick={() => updateStatus(CycleStatus.VOTING)}
                  className="flex items-center px-4 py-2 bg-purple-600 text-white rounded-lg hover:bg-purple-700 text-sm font-medium transition-colors shadow-sm"
                >
                  <Play className="w-4 h-4 mr-2" />
                  Start Voting
                </button>
              )}
              {activeCycle.status === CycleStatus.VOTING && (
                <button 
                  onClick={() => updateStatus(CycleStatus.CLOSED)}
                  className="flex items-center px-4 py-2 bg-red-600 text-white rounded-lg hover:bg-red-700 text-sm font-medium transition-colors shadow-sm"
                >
                  <StopCircle className="w-4 h-4 mr-2" />
                  Close Cycle
                </button>
              )}
              {activeCycle.status === CycleStatus.CLOSED && (
                <button disabled className="flex items-center px-4 py-2 bg-gray-100 text-gray-400 rounded-lg cursor-not-allowed text-sm font-medium border border-gray-200">
                  <Archive className="w-4 h-4 mr-2" />
                  Archived
                </button>
              )}
            </div>
          </div>
        ) : (
           <div className="text-center py-10 bg-gray-50 rounded-xl border border-dashed border-gray-300 text-gray-500">
             No active cycle found. Create one to begin.
           </div>
        )}
      </div>

      {/* Results Visualization */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Chart */}
        <div className="lg:col-span-2 bg-white rounded-xl shadow-sm border border-gray-200 p-6">
          <div className="flex items-center justify-between mb-6">
            <h2 className="text-lg font-bold text-gray-900">Real-time Results</h2>
            <button 
              onClick={handleExport}
              disabled={stats.length === 0}
              className="flex items-center text-sm font-medium text-gray-600 hover:text-indigo-600 disabled:opacity-50 transition-colors"
            >
              <Download className="w-4 h-4 mr-1.5" />
              Export CSV
            </button>
          </div>

          {stats.length > 0 ? (
            <div className="h-80 w-full">
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={stats} margin={{ top: 20, right: 30, left: 20, bottom: 5 }}>
                  <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f0f0f0" />
                  <XAxis dataKey="nomineeName" axisLine={false} tickLine={false} tick={{fill: '#6b7280', fontSize: 12}} dy={10} />
                  <YAxis axisLine={false} tickLine={false} allowDecimals={false} tick={{fill: '#6b7280', fontSize: 12}} />
                  <Tooltip 
                    cursor={{ fill: '#f9fafb' }}
                    contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 10px 15px -3px rgba(0, 0, 0, 0.1)' }}
                  />
                  <Legend />
                  <Bar dataKey="nominationCount" name="Nominations" fill="#818cf8" radius={[4, 4, 0, 0]} />
                  <Bar dataKey="voteCount" name="Votes" fill="#4f46e5" radius={[4, 4, 0, 0]} />
                </BarChart>
              </ResponsiveContainer>
            </div>
          ) : (
            <div className="h-80 w-full flex items-center justify-center bg-gray-50 rounded-lg text-gray-400 border border-dashed border-gray-200">
              No data available for this cycle yet.
            </div>
          )}
        </div>

        {/* Top Candidates List */}
        <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-6">
          <h2 className="text-lg font-bold text-gray-900 mb-4">Leaderboard</h2>
          <div className="space-y-3">
            {stats.length > 0 ? (
              stats.slice(0, 5).map((stat, index) => (
                <div key={stat.nomineeId} className="flex items-center p-3 hover:bg-gray-50 rounded-lg transition-colors border border-transparent hover:border-gray-100">
                  <div className={`w-8 h-8 flex items-center justify-center rounded-full font-bold text-sm mr-3 shadow-sm ${
                    index === 0 ? 'bg-yellow-100 text-yellow-700 ring-1 ring-yellow-200' :
                    index === 1 ? 'bg-gray-100 text-gray-700 ring-1 ring-gray-200' :
                    index === 2 ? 'bg-orange-100 text-orange-800 ring-1 ring-orange-200' :
                    'bg-white border text-gray-500'
                  }`}>
                    {index + 1}
                  </div>
                  <div className="flex-1 min-w-0">
                    <p className="text-sm font-semibold text-gray-900 truncate">{stat.nomineeName}</p>
                    <p className="text-xs text-gray-500">{stat.voteCount} votes • {stat.nominationCount} nominations</p>
                  </div>
                  <div className="text-xs font-bold text-indigo-600 bg-indigo-50 px-2.5 py-1 rounded-full">
                    {Math.round((stat.voteCount / (stats.reduce((acc, curr) => acc + curr.voteCount, 0) || 1)) * 100)}%
                  </div>
                </div>
              ))
            ) : (
              <p className="text-sm text-gray-500 text-center py-8">No votes cast yet.</p>
            )}
          </div>
        </div>
      </div>

      {/* Employee Directory Section */}
      <div className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden">
        <div className="p-6 border-b border-gray-200 flex flex-col sm:flex-row sm:items-center justify-between gap-4">
          <div>
            <h2 className="text-lg font-bold text-gray-900">Employee Directory</h2>
            <p className="text-sm text-gray-500 mt-1">Manage user accounts and access.</p>
          </div>
          <button 
            onClick={() => setIsAddUserModalOpen(true)}
            className="flex items-center justify-center px-4 py-2.5 bg-gray-900 text-white rounded-lg hover:bg-gray-800 text-sm font-medium transition-all shadow-sm active:scale-95"
          >
            <UserPlus className="w-4 h-4 mr-2" />
            Add Employee
          </button>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-sm text-left">
            <thead className="bg-gray-50 text-gray-600 font-semibold border-b border-gray-200 uppercase tracking-wider text-xs">
              <tr>
                <th className="px-6 py-4">Name</th>
                <th className="px-6 py-4">Email</th>
                <th className="px-6 py-4">Department</th>
                <th className="px-6 py-4">Role</th>
                <th className="px-6 py-4">Status</th>
                <th className="px-6 py-4 text-right">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-100 bg-white">
              {users.map(user => (
                <tr key={user.id} className="hover:bg-gray-50 transition-colors">
                  <td className="px-6 py-4">
                    <div className="flex items-center">
                      {user.avatar ? (
                        <img 
                          className="h-9 w-9 rounded-full object-cover mr-3 border border-gray-200" 
                          src={user.avatar} 
                          alt={user.name} 
                        />
                      ) : (
                        <div className="h-9 w-9 rounded-full bg-gradient-to-br from-indigo-100 to-indigo-50 flex items-center justify-center text-indigo-700 font-bold text-sm mr-3 border border-indigo-200 shadow-sm">
