                        onClick={() => toggleUserStatus(user)}
                        className={`p-1.5 rounded-lg transition-colors ${
                          user.status === 'ACTIVE' 
                            ? 'text-gray-500 hover:text-red-600 hover:bg-red-50' 
                            : 'text-red-600 hover:text-green-600 hover:bg-green-50'
