  }
];

const INITIAL_CYCLES: Cycle[] = [];

// Helper to access LocalStorage safely
const getStorage = <T,>(key: string, initial: T): T => {
  const stored = localStorage.getItem(key);
  if (!stored) {
    localStorage.setItem(key, JSON.stringify(initial));
    return initial;
