    <Link
      to={to}
      className={`flex items-center px-4 py-3 text-sm font-medium transition-colors rounded-lg mb-1 ${
        isActive(to)
          ? 'bg-indigo-50 text-indigo-700'
          : 'text-gray-600 hover:bg-gray-100 hover:text-gray-900'
