import React, { createContext, useContext, useState, useEffect, ReactNode } from 'react';
import { 
  signInWithEmailAndPassword, 
  createUserWithEmailAndPassword, 
  signOut, 
  onAuthStateChanged,
  User as FirebaseUser
} from 'firebase/auth';
import { auth } from '../services/firebase';
import { User, AuthState, UserRole } from '../types';
import { dbService } from '../services/db';

interface AuthContextType extends AuthState {
  login: (email: string, password?: string) => Promise<boolean>;
  register: (data: Omit<User, 'id' | 'status' | 'role'>) => Promise<boolean>;
  logout: () => void;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export const AuthProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [state, setState] = useState<AuthState>({
    user: null,
    isAuthenticated: false,
  });
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, async (firebaseUser: FirebaseUser | null) => {
      if (firebaseUser) {
        try {
          // Fetch the user profile from Firestore
          const userProfile = await dbService.getUserById(firebaseUser.uid);

          if (userProfile) {
            setState({ 
              user: userProfile, 
              isAuthenticated: true 
            });
          } else {
             // Handle case where auth exists but db profile doesn't (e.g. registration interrupted)
             // We don't log them out immediately to allow for potential recovery flows if needed,
             // but we don't set them as authenticated in the app context yet.
             console.warn("Auth user found but no Firestore profile");
             setState({ user: null, isAuthenticated: false });
          }
        } catch (error) {
          console.error("Error fetching user profile:", error);
          setState({ user: null, isAuthenticated: false });
        }
      } else {
        setState({ user: null, isAuthenticated: false });
      }
      setLoading(false);
    });

    return () => unsubscribe();
  }, []);

  const login = async (email: string, password?: string): Promise<boolean> => {
    if (!password) return false;
    try {
      await signInWithEmailAndPassword(auth, email, password);
      // State updates are handled by the onAuthStateChanged listener
      return true;
    } catch (error) {
      console.error("Login failed", error);
      throw error;
    }
  };

  const register = async (data: Omit<User, 'id' | 'status' | 'role'>): Promise<boolean> => {
    if (!data.password) throw new Error("Password is required");
    try {
      // 1. Create Auth User
      const userCredential = await createUserWithEmailAndPassword(auth, data.email, data.password);

      // 2. Create Firestore Profile
      await dbService.createUserProfile(userCredential.user.uid, {
        name: data.name,
        email: data.email,
        department: data.department,
        role: UserRole.EMPLOYEE
      });

      return true;
    } catch (error: any) {
      // SPECIAL HANDLING: If email already exists, check if we need to repair a broken profile
      if (error.code === 'auth/email-already-in-use') {
        try {
          // Attempt to sign in with the provided password to verify ownership
          const userCredential = await signInWithEmailAndPassword(auth, data.email, data.password);

          // Check if profile exists
          const existingProfile = await dbService.getUserById(userCredential.user.uid);

          if (!existingProfile) {
            // RECOVERY: Auth exists, Password matches, but Profile is missing. Create it now.
            await dbService.createUserProfile(userCredential.user.uid, {
              name: data.name,
              email: data.email,
              department: data.department,
              role: UserRole.EMPLOYEE
            });
            return true;
          } else {
            // Profile exists, so this is just a duplicate registration attempt
            throw new Error("This email is already registered. Please log in.");
          }
        } catch (loginError: any) {
          // If login failed (wrong password) or manual throw above
          if (loginError.message === "This email is already registered. Please log in.") {
            throw loginError;
          }
          throw new Error("Email already in use. If this is you, please log in.");
        }
      }

      console.error("Registration failed", error);
      throw error;
    }
  };

  const logout = async () => {
    try {
      await signOut(auth);
      setState({ user: null, isAuthenticated: false });
    } catch (error) {
      console.error("Logout failed", error);
    }
  };

  if (loading) {
    return <div className="min-h-screen flex items-center justify-center bg-gray-50 text-gray-400">Loading application...</div>;
  }

  return (
    <AuthContext.Provider value={{ ...state, login, register, logout }}>
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
};

