        where("status", "in", [CycleStatus.NOMINATION, CycleStatus.VOTING])
      );
      const snapshotActive = await getDocs(qActive);
      if (!snapshotActive.empty) {
          // Return the first active one found
          return { id: snapshotActive.docs[0].id, ...snapshotActive.docs[0].data() } as Cycle;
      }

      // If no active cycle, try to get the most recent closed one
      // We wrap this in try-catch because it might require an index that isn't built yet
      // or specific permissions for closed cycles
      try {
        const qRecent = query(
          collection(db, 'cycles'), 
