import { 
  collection, 
  getDocs, 
  doc, 
  setDoc, 
  updateDoc, 
  query, 
  where, 
  addDoc,
  getDoc,
  writeBatch,
  getCountFromServer,
  orderBy,
  limit
} from "firebase/firestore";
import { db } from "./firebase";
import { User, UserRole, Cycle, CycleStatus, Nomination, Vote, CycleStats } from '../types';

// Helper to handle Firestore permission errors gracefully
const safeGetDocs = async (q: any) => {
  try {
    return await getDocs(q);
  } catch (error: any) {
    console.warn("Firestore query failed (likely permissions):", error.code, error.message);
    // Return an empty structure that resembles a snapshot to prevent crashes
    return { empty: true, docs: [] };
  }
};

// Database Service with Firestore
export const dbService = {
  getUsers: async (): Promise<User[]> => {
    try {
      const snapshot = await safeGetDocs(collection(db, 'users'));
      return snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as User));
    } catch (e) {
      return [];
    }
  },

  getUserById: async (id: string): Promise<User | undefined> => {
    const docRef = doc(db, 'users', id);
    try {
      const docSnap = await getDoc(docRef);
      if (docSnap.exists()) {
        return { id: docSnap.id, ...docSnap.data() } as User;
      }
    } catch (error) {
      console.warn("Error fetching user profile:", error);
    }
    return undefined;
  },

  getEmployees: async (): Promise<User[]> => {
    try {
      // Some security rules block listing all users. 
      const q = query(collection(db, 'users'), where("role", "==", UserRole.EMPLOYEE));
      const snapshot = await safeGetDocs(q);
      return snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as User));
    } catch (e) {
      console.warn("Could not load employees list");
      return [];
    }
  },

  // Used for registering a new user linked to Firebase Auth UID
  createUserProfile: async (uid: string, user: Omit<User, 'id' | 'status'>): Promise<void> => {
    let role = user.role;

    try {
      // Attempt to check if this is the first user
      const coll = collection(db, 'users');
      // If permission denied here, we catch it and skip auto-admin assignment
      const snapshot = await getCountFromServer(coll);
      const isFirstUser = snapshot.data().count === 0;
      if (isFirstUser) {
        role = UserRole.ADMIN;
      }
    } catch (error) {
      // Silently ignore permission errors for count()
    }

    const newUserRef = doc(db, 'users', uid);
    const newUser: User = {
      ...user,
      id: uid,
      role: role,
      status: 'ACTIVE'
    };

    if ('password' in newUser) {
      delete newUser.password;
    }

    await setDoc(newUserRef, newUser);
  },

  addUser: async (user: Omit<User, 'id' | 'status'>): Promise<void> => {
    try {
        const q = query(collection(db, 'users'), where("email", "==", user.email));
        const querySnapshot = await getDocs(q);
        if (!querySnapshot.empty) {
        throw new Error("User with this email already exists");
        }
    } catch (e: any) {
        if (e.message?.includes("exists")) throw e;
        // If permission error on check, proceed blindly (Firestore rules will block if needed)
    }

    const newUserRef = doc(collection(db, 'users'));
    const newUser: User = {
      ...user,
      id: newUserRef.id,
      status: 'ACTIVE'
    };

    if ('password' in newUser) {
      delete newUser.password;
    }

    await setDoc(newUserRef, newUser);
  },

  updateUser: async (user: User): Promise<void> => {
    const userRef = doc(db, 'users', user.id);
    const userData = { ...user };
    if ('password' in userData) delete userData.password;
    await updateDoc(userRef, userData);
  },

  getCycles: async (): Promise<Cycle[]> => {
    try {
      const snapshot = await safeGetDocs(collection(db, 'cycles'));
      return snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Cycle));
    } catch (e) {
      return [];
    }
  },

  getActiveCycle: async (): Promise<Cycle | undefined> => {
    // Strategy: Try getting specific active states individually. 
    // This avoids "IN" queries which can trigger permission issues on some rule sets
    try {
      // 1. Try Nomination
      const qNom = query(collection(db, 'cycles'), where("status", "==", CycleStatus.NOMINATION), limit(1));
      const snapNom = await safeGetDocs(qNom);
      if (!snapNom.empty) return { id: snapNom.docs[0].id, ...snapNom.docs[0].data() } as Cycle;

      // 2. Try Voting
      const qVote = query(collection(db, 'cycles'), where("status", "==", CycleStatus.VOTING), limit(1));
      const snapVote = await safeGetDocs(qVote);
      if (!snapVote.empty) return { id: snapVote.docs[0].id, ...snapVote.docs[0].data() } as Cycle;

      // 3. Fallback: Get most recent Closed
      const qClosed = query(
          collection(db, 'cycles'), 
          where("status", "==", CycleStatus.CLOSED), 
          orderBy("year", "desc"), 
          orderBy("month", "desc"), 
          limit(1)
      );
      // This might fail if index is missing, catch specifically
      try {
          const snapClosed = await getDocs(qClosed);
          if (!snapClosed.empty) return { id: snapClosed.docs[0].id, ...snapClosed.docs[0].data() } as Cycle;
      } catch (e) {
          // ignore index errors or permission errors on closed cycles
      }

    } catch (error) {
      console.warn("Error in getActiveCycle, returning undefined to prevent crash");
    }

    return undefined;
  },

  createCycle: async (month: number, year: number): Promise<Cycle> => {
    const batch = writeBatch(db);

    try {
        const qOpen = query(collection(db, 'cycles'), where("status", "!=", CycleStatus.CLOSED));
        const snapshot = await getDocs(qOpen);
        snapshot.docs.forEach((doc) => {
            batch.update(doc.ref, { status: CycleStatus.CLOSED });
        });
    } catch (e) {
        // Continue even if we can't close old ones (maybe we lack list permission)
    }

    const newCycleRef = doc(collection(db, 'cycles'));
    const newCycle: Cycle = {
      id: newCycleRef.id,
      month,
      year,
      status: CycleStatus.NOMINATION
    };
    batch.set(newCycleRef, newCycle);

    await batch.commit();
    return newCycle;
  },

  updateCycleStatus: async (cycleId: string, status: CycleStatus): Promise<void> => {
    const cycleRef = doc(db, 'cycles', cycleId);
    await updateDoc(cycleRef, { status });
  },

  setCycleWinner: async (cycleId: string, winnerId: string): Promise<void> => {
    const cycleRef = doc(db, 'cycles', cycleId);
    await updateDoc(cycleRef, { winnerId });
  },

  getNominations: async (cycleId: string): Promise<Nomination[]> => {
    const q = query(collection(db, 'nominations'), where("cycleId", "==", cycleId));
    const snapshot = await safeGetDocs(q);
    return snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Nomination));
  },

  getUserNomination: async (userId: string, cycleId: string): Promise<Nomination | undefined> => {
    const q = query(
      collection(db, 'nominations'), 
      where("nominatorId", "==", userId),
      where("cycleId", "==", cycleId)
    );
    const snapshot = await safeGetDocs(q);
    if (!snapshot.empty) {
      return { id: snapshot.docs[0].id, ...snapshot.docs[0].data() } as Nomination;
    }
    return undefined;
  },

  addNomination: async (nominatorId: string, nomineeId: string, cycleId: string, reason: string): Promise<void> => {
    const existing = await dbService.getUserNomination(nominatorId, cycleId);
    if (existing) {
      throw new Error("You have already nominated someone this cycle.");
    }

    const newNomRef = doc(collection(db, 'nominations'));
    const newNomination: Nomination = {
      id: newNomRef.id,
      nominatorId,
      nomineeId,
      cycleId,
      reason,
      timestamp: Date.now()
    };
    await setDoc(newNomRef, newNomination);
  },

  getVotes: async (cycleId: string): Promise<Vote[]> => {
    const q = query(collection(db, 'votes'), where("cycleId", "==", cycleId));
    const snapshot = await safeGetDocs(q);
    return snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Vote));
  },

  getUserVote: async (userId: string, cycleId: string): Promise<Vote | undefined> => {
    const q = query(
      collection(db, 'votes'), 
      where("voterId", "==", userId),
      where("cycleId", "==", cycleId)
    );
    const snapshot = await safeGetDocs(q);
    if (!snapshot.empty) {
      return { id: snapshot.docs[0].id, ...snapshot.docs[0].data() } as Vote;
    }
    return undefined;
  },

  addVote: async (voterId: string, nomineeId: string, cycleId: string): Promise<void> => {
    const existing = await dbService.getUserVote(voterId, cycleId);
    if (existing) {
      throw new Error("You have already voted this cycle.");
    }

    const newVoteRef = doc(collection(db, 'votes'));
    const newVote: Vote = {
      id: newVoteRef.id,
      voterId,
      nomineeId,
      cycleId,
      timestamp: Date.now()
    };
    await setDoc(newVoteRef, newVote);
  },

  getCycleStats: async (cycleId: string): Promise<CycleStats[]> => {
    try {
        const nominations = await dbService.getNominations(cycleId);
        const votes = await dbService.getVotes(cycleId);
        const employees = await dbService.getUsers(); // This might return empty if permissions deny listing

        const statsMap = new Map<string, CycleStats>();

        nominations.forEach(nom => {
        if (!statsMap.has(nom.nomineeId)) {
            const emp = employees.find(e => e.id === nom.nomineeId);
            // If we can't list employees, we might only have ID. 
            // Fallback to "Unknown Employee" or just ID if name missing
            const name = emp ? emp.name : "Employee"; 

            statsMap.set(nom.nomineeId, {
                nomineeId: nom.nomineeId,
                nomineeName: name,
                nominationCount: 0,
                voteCount: 0
            });
        }
        const stat = statsMap.get(nom.nomineeId);
        if (stat) stat.nominationCount++;
        });

        votes.forEach(vote => {
        if (!statsMap.has(vote.nomineeId)) {
            // Logic for votes without prior nominations (shouldn't happen in strict flow but possible)
            const emp = employees.find(e => e.id === vote.nomineeId);
            const name = emp ? emp.name : "Employee"; 

            statsMap.set(vote.nomineeId, {
                nomineeId: vote.nomineeId,
                nomineeName: name,
                nominationCount: 0,
                voteCount: 0
            });
        }
        const stat = statsMap.get(vote.nomineeId);
        if (stat) stat.voteCount++;
        });

        return Array.from(statsMap.values()).sort((a, b) => b.voteCount - a.voteCount);
    } catch (e) {
        console.warn("Failed to generate cycle stats");
        return [];
    }
  },

  getEmployeeHistory: async (userId: string) => {
    try {
        const cycles = await dbService.getCycles();
        const allNominations = await safeGetDocs(collection(db, 'nominations'));
        const nominations = allNominations.docs.map(d => d.data() as Nomination);

        const allVotes = await safeGetDocs(collection(db, 'votes'));
        const votes = allVotes.docs.map(d => d.data() as Vote);

        const users = await dbService.getUsers();

        return cycles.map(cycle => {
        const myNomination = nominations.find(n => n.cycleId === cycle.id && n.nominatorId === userId);
        const myVote = votes.find(v => v.cycleId === cycle.id && v.voterId === userId);
        const receivedNoms = nominations.filter(n => n.cycleId === cycle.id && n.nomineeId === userId);
        const receivedVotes = votes.filter(v => v.cycleId === cycle.id && v.nomineeId === userId).length;

        const nomineeName = myNomination ? users.find(u => u.id === myNomination.nomineeId)?.name || 'Unknown' : undefined;

        return {
            cycle,
            activity: {
            nominated: myNomination ? { name: nomineeName, reason: myNomination.reason } : null,
            voted: !!myVote,
            receivedNominations: receivedNoms.map(n => ({
                from: users.find(u => u.id === n.nominatorId)?.name || 'Unknown',
                reason: n.reason
            })),
            votesReceived: receivedVotes
            }
        };
        }).sort((a, b) => (b.cycle.year * 12 + b.cycle.month) - (a.cycle.year * 12 + a.cycle.month));
    } catch (e) {
        return [];
    }
  }
};

import React, { useEffect, useState } from 'react';
import { dbService } from '../services/db';
import { Cycle, CycleStatus, CycleStats, User, UserRole } from '../types';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer } from 'recharts';
import { Download, Plus, Play, StopCircle, Archive, Pencil, Power, X, UserPlus, Calendar, Award, MessageSquare, CheckCircle, Vote, Trophy, Lock } from 'lucide-react';

const MONTHS = [
  'January', 'February', 'March', 'April', 'May', 'June',
  'July', 'August', 'September', 'October', 'November', 'December'
];

export const AdminDashboard: React.FC = () => {
  const [activeCycle, setActiveCycle] = useState<Cycle | undefined>();
  const [stats, setStats] = useState<CycleStats[]>([]);
  const [winner, setWinner] = useState<User | null>(null);

  // Cycle Creation State
  const [isCreateCycleModalOpen, setIsCreateCycleModalOpen] = useState(false);
  const [createCycleForm, setCreateCycleForm] = useState({
    month: new Date().getMonth(),
    year: new Date().getFullYear()
  });
  const [createCycleError, setCreateCycleError] = useState('');

  // Employee Management State
  const [users, setUsers] = useState<User[]>([]);
  const [isEditModalOpen, setIsEditModalOpen] = useState(false);
  const [editingUser, setEditingUser] = useState<User | null>(null);

  // Profile View State
  const [viewingUser, setViewingUser] = useState<User | null>(null);
  const [userHistory, setUserHistory] = useState<any[]>([]);

  // Add Employee Modal State
  const [isAddUserModalOpen, setIsAddUserModalOpen] = useState(false);
  const [newUser, setNewUser] = useState({
    name: '',
    email: '',
    department: '',
    role: UserRole.EMPLOYEE,
    password: ''
  });
  const [addUserError, setAddUserError] = useState('');

  const refreshData = async () => {
    try {
      const cycle = await dbService.getActiveCycle();
      setActiveCycle(cycle);
      if (cycle) {
        try {
          const stats = await dbService.getCycleStats(cycle.id);
          setStats(stats || []);
          if (cycle.winnerId) {
            const winnerUser = await dbService.getUserById(cycle.winnerId);
            setWinner(winnerUser || null);
          } else {
            setWinner(null);
          }
        } catch (statError) {
          console.warn("Failed to load cycle stats", statError);
          setStats([]);
        }
      }

      try {
        const allUsers = await dbService.getUsers();
        setUsers(allUsers || []);
      } catch (userError) {
        console.warn("Failed to load users for admin", userError);
        setUsers([]);
      }
    } catch (error) {
      console.error("Failed to load admin data", error);
    }
  };

  useEffect(() => {
    refreshData();
  }, []);

  const handleOpenCreateCycle = () => {
    const now = new Date();
    setCreateCycleForm({ month: now.getMonth(), year: now.getFullYear() });
    setCreateCycleError('');
    setIsCreateCycleModalOpen(true);
  };

  const handleCreateCycleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setCreateCycleError('');

    const now = new Date();
    const selectedDate = new Date(createCycleForm.year, createCycleForm.month);
    const currentDate = new Date(now.getFullYear(), now.getMonth());

    if (selectedDate > currentDate) {
      setCreateCycleError("Cannot start a cycle for a future month.");
      return;
    }

    try {
        await dbService.createCycle(createCycleForm.month, createCycleForm.year);
        setIsCreateCycleModalOpen(false);
        refreshData();
    } catch (e: any) {
        setCreateCycleError("Failed to create cycle: " + e.message);
    }
  };

  const updateStatus = async (status: CycleStatus) => {
    if (activeCycle) {
      await dbService.updateCycleStatus(activeCycle.id, status);
      refreshData();
    }
  };

  const handleDeclareWinner = async () => {
    if (!activeCycle || stats.length === 0) return;

    // Assumes stats are sorted by vote count desc
    const leader = stats[0];
    if (leader.voteCount > 0) {
      await dbService.setCycleWinner(activeCycle.id, leader.nomineeId);
      await dbService.updateCycleStatus(activeCycle.id, CycleStatus.CLOSED);
      refreshData();
    }
  };

  const handleExport = async () => {
    if (!activeCycle) return;

    // Convert stats to CSV
    const headers = ['Nominee Name', 'Department', 'Nominations', 'Votes'];
    const users = await dbService.getUsers();

    const rows = stats.map(s => {
      const u = users.find(user => user.id === s.nomineeId);
      return [
        s.nomineeName,
        u?.department || 'N/A',
        s.nominationCount,
        s.voteCount
      ].join(',');
    });

    const csvContent = "data:text/csv;charset=utf-8," + [headers.join(','), ...rows].join('\n');
    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", `results_${MONTHS[activeCycle.month]}_${activeCycle.year}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  // User Management Functions
  const handleEditClick = (user: User) => {
    setEditingUser({ ...user });
    setIsEditModalOpen(true);
  };

  const handleViewProfile = async (user: User) => {
    setViewingUser(user);
    const history = await dbService.getEmployeeHistory(user.id);
    setUserHistory(history);
  };

  const handleUserUpdate = async (e: React.FormEvent) => {
    e.preventDefault();
    if (editingUser) {
      await dbService.updateUser(editingUser);
      setIsEditModalOpen(false);
      setEditingUser(null);
      refreshData();
    }
  };

  const toggleUserStatus = async (user: User) => {
    const newStatus = user.status === 'ACTIVE' ? 'INACTIVE' : 'ACTIVE';
    await dbService.updateUser({ ...user, status: newStatus });
    refreshData();
  };

  const handleAddUserSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setAddUserError('');
    try {
      await dbService.addUser({
        name: newUser.name,
        email: newUser.email,
        department: newUser.department,
        role: newUser.role,
        password: newUser.password || 'password123' // Fallback default
      });
      setIsAddUserModalOpen(false);
      setNewUser({
        name: '',
        email: '',
        department: '',
        role: UserRole.EMPLOYEE,
        password: ''
      });
      refreshData();
    } catch (err: any) {
      setAddUserError(err.message);
    }
  };

