import { 
  collection, 
  getDocs, 
  doc, 
  setDoc, 
  updateDoc, 
  query, 
  where, 
  addDoc,
  getDoc,
  writeBatch,
  getCountFromServer,
  orderBy,
  limit
} from "firebase/firestore";
import { db } from "./firebase";
import { User, UserRole, Cycle, CycleStatus, Nomination, Vote, CycleStats } from '../types';

// Helper to handle Firestore permission errors gracefully
const safeGetDocs = async (q: any) => {
  try {
    return await getDocs(q);
  } catch (error: any) {
    // Suppress permission errors in console to avoid noise
    if (error.code !== 'permission-denied') {
        console.warn("Firestore query failed:", error.code, error.message);
    }
    // Return an empty structure that resembles a snapshot to prevent crashes
    return { empty: true, docs: [] };
  }
};

// Database Service with Firestore
export const dbService = {
  getUsers: async (): Promise<User[]> => {
    try {
      const snapshot = await safeGetDocs(collection(db, 'users'));
      return snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as User));
    } catch (e) {
      return [];
    }
  },

  getUserById: async (id: string): Promise<User | undefined> => {
    const docRef = doc(db, 'users', id);
    try {
      const docSnap = await getDoc(docRef);
      if (docSnap.exists()) {
        return { id: docSnap.id, ...docSnap.data() } as User;
      }
    } catch (error) {
      // Ignore permission errors during profile fetch (e.g. self-registration flow)
    }
    return undefined;
  },

  getEmployees: async (): Promise<User[]> => {
    try {
      // Some security rules block listing all users. 
      const q = query(collection(db, 'users'), where("role", "==", UserRole.EMPLOYEE));
      const snapshot = await safeGetDocs(q);
      return snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as User));
    } catch (e) {
      return [];
    }
  },

  // Used for registering a new user linked to Firebase Auth UID
  createUserProfile: async (uid: string, user: Omit<User, 'id' | 'status'>): Promise<void> => {
    let role = user.role;

    try {
      // Attempt to check if this is the first user
      const coll = collection(db, 'users');
      // If permission denied here, we catch it and skip auto-admin assignment
      const snapshot = await getCountFromServer(coll);
      const isFirstUser = snapshot.data().count === 0;
      if (isFirstUser) {
        role = UserRole.ADMIN;
      }
    } catch (error) {
      // Silently ignore permission errors for count()
    }

    const newUserRef = doc(db, 'users', uid);
    const newUser: User = {
      ...user,
      id: uid,
      role: role,
      status: 'ACTIVE'
    };

    if ('password' in newUser) {
      delete newUser.password;
    }

    await setDoc(newUserRef, newUser);
  },

  addUser: async (user: Omit<User, 'id' | 'status'>): Promise<void> => {
    try {
        const q = query(collection(db, 'users'), where("email", "==", user.email));
        const querySnapshot = await getDocs(q);
        if (!querySnapshot.empty) {
        throw new Error("User with this email already exists");
        }
    } catch (e: any) {
        if (e.message?.includes("exists")) throw e;
        // If permission error on check, proceed blindly (Firestore rules will block if needed)
    }

    const newUserRef = doc(collection(db, 'users'));
    const newUser: User = {
      ...user,
      id: newUserRef.id,
      status: 'ACTIVE'
    };

    if ('password' in newUser) {
      delete newUser.password;
    }

    await setDoc(newUserRef, newUser);
  },

  updateUser: async (user: User): Promise<void> => {
    const userRef = doc(db, 'users', user.id);
    const userData = { ...user };
    if ('password' in userData) delete userData.password;
    await updateDoc(userRef, userData);
  },

  getCycles: async (): Promise<Cycle[]> => {
    try {
      const snapshot = await safeGetDocs(collection(db, 'cycles'));
      return snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Cycle));
    } catch (e) {
      return [];
    }
  },

  getActiveCycle: async (): Promise<Cycle | undefined> => {
    // Strategy: Try getting specific active states individually. 
    // This avoids "IN" queries which can trigger permission issues on some rule sets
    try {
      // 1. Try Nomination
      const qNom = query(collection(db, 'cycles'), where("status", "==", CycleStatus.NOMINATION), limit(1));
      const snapNom = await safeGetDocs(qNom);
      if (!snapNom.empty) return { id: snapNom.docs[0].id, ...snapNom.docs[0].data() } as Cycle;

      // 2. Try Voting
      const qVote = query(collection(db, 'cycles'), where("status", "==", CycleStatus.VOTING), limit(1));
      const snapVote = await safeGetDocs(qVote);
      if (!snapVote.empty) return { id: snapVote.docs[0].id, ...snapVote.docs[0].data() } as Cycle;

      // 3. Fallback: Get most recent Closed
      const qClosed = query(
          collection(db, 'cycles'), 
          where("status", "==", CycleStatus.CLOSED), 
          orderBy("year", "desc"), 
          orderBy("month", "desc"), 
          limit(1)
      );
      // This might fail if index is missing, catch specifically
      try {
          const snapClosed = await getDocs(qClosed);
          if (!snapClosed.empty) return { id: snapClosed.docs[0].id, ...snapClosed.docs[0].data() } as Cycle;
      } catch (e) {
          // ignore index errors or permission errors on closed cycles
      }

    } catch (error) {
      // Ignore errors
    }

    return undefined;
  },

  createCycle: async (month: number, year: number): Promise<Cycle> => {
    const batch = writeBatch(db);

    try {
        const qOpen = query(collection(db, 'cycles'), where("status", "!=", CycleStatus.CLOSED));
        const snapshot = await getDocs(qOpen);
        snapshot.docs.forEach((doc) => {
            batch.update(doc.ref, { status: CycleStatus.CLOSED });
        });
    } catch (e) {
        // Continue even if we can't close old ones (maybe we lack list permission)
    }

    const newCycleRef = doc(collection(db, 'cycles'));
    const newCycle: Cycle = {
      id: newCycleRef.id,
      month,
      year,
      status: CycleStatus.NOMINATION
    };
    batch.set(newCycleRef, newCycle);

    await batch.commit();
    return newCycle;
  },

  updateCycleStatus: async (cycleId: string, status: CycleStatus): Promise<void> => {
    const cycleRef = doc(db, 'cycles', cycleId);
    await updateDoc(cycleRef, { status });
  },

  setCycleWinner: async (cycleId: string, winnerId: string): Promise<void> => {
    const cycleRef = doc(db, 'cycles', cycleId);
    await updateDoc(cycleRef, { winnerId });
  },

  getNominations: async (cycleId: string): Promise<Nomination[]> => {
    const q = query(collection(db, 'nominations'), where("cycleId", "==", cycleId));
    const snapshot = await safeGetDocs(q);
    return snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Nomination));
  },

  getUserNomination: async (userId: string, cycleId: string): Promise<Nomination | undefined> => {
    const q = query(
      collection(db, 'nominations'), 
      where("nominatorId", "==", userId),
      where("cycleId", "==", cycleId)
    );
    const snapshot = await safeGetDocs(q);
    if (!snapshot.empty) {
      return { id: snapshot.docs[0].id, ...snapshot.docs[0].data() } as Nomination;
    }
    return undefined;
  },

  addNomination: async (nominatorId: string, nomineeId: string, cycleId: string, reason: string): Promise<void> => {
    const existing = await dbService.getUserNomination(nominatorId, cycleId);
    if (existing) {
      throw new Error("You have already nominated someone this cycle.");
    }

    const newNomRef = doc(collection(db, 'nominations'));
    const newNomination: Nomination = {
      id: newNomRef.id,
      nominatorId,
      nomineeId,
      cycleId,
      reason,
      timestamp: Date.now()
    };
    await setDoc(newNomRef, newNomination);
  },

  getVotes: async (cycleId: string): Promise<Vote[]> => {
    const q = query(collection(db, 'votes'), where("cycleId", "==", cycleId));
    const snapshot = await safeGetDocs(q);
    return snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Vote));
  },

  getUserVote: async (userId: string, cycleId: string): Promise<Vote | undefined> => {
    const q = query(
      collection(db, 'votes'), 
      where("voterId", "==", userId),
      where("cycleId", "==", cycleId)
    );
    const snapshot = await safeGetDocs(q);
    if (!snapshot.empty) {
      return { id: snapshot.docs[0].id, ...snapshot.docs[0].data() } as Vote;
    }
    return undefined;
  },

  addVote: async (voterId: string, nomineeId: string, cycleId: string): Promise<void> => {
    const existing = await dbService.getUserVote(voterId, cycleId);
    if (existing) {
      throw new Error("You have already voted this cycle.");
    }

    const newVoteRef = doc(collection(db, 'votes'));
    const newVote: Vote = {
      id: newVoteRef.id,
      voterId,
      nomineeId,
      cycleId,
      timestamp: Date.now()
    };
    await setDoc(newVoteRef, newVote);
  },

  getCycleStats: async (cycleId: string): Promise<CycleStats[]> => {
    try {
        const nominations = await dbService.getNominations(cycleId);
        const votes = await dbService.getVotes(cycleId);
        const employees = await dbService.getUsers(); // This might return empty if permissions deny listing

        const statsMap = new Map<string, CycleStats>();

        nominations.forEach(nom => {
        if (!statsMap.has(nom.nomineeId)) {
            const emp = employees.find(e => e.id === nom.nomineeId);
            // If we can't list employees, we might only have ID. 
            // Fallback to "Unknown Employee" or just ID if name missing
            const name = emp ? emp.name : "Employee"; 

            statsMap.set(nom.nomineeId, {
                nomineeId: nom.nomineeId,
                nomineeName: name,
                nominationCount: 0,
                voteCount: 0
            });
        }
        const stat = statsMap.get(nom.nomineeId);
        if (stat) stat.nominationCount++;
        });

        votes.forEach(vote => {
        if (!statsMap.has(vote.nomineeId)) {
            // Logic for votes without prior nominations (shouldn't happen in strict flow but possible)
            const emp = employees.find(e => e.id === vote.nomineeId);
            const name = emp ? emp.name : "Employee"; 

            statsMap.set(vote.nomineeId, {
                nomineeId: vote.nomineeId,
                nomineeName: name,
                nominationCount: 0,
                voteCount: 0
            });
        }
        const stat = statsMap.get(vote.nomineeId);
        if (stat) stat.voteCount++;
        });

        return Array.from(statsMap.values()).sort((a, b) => b.voteCount - a.voteCount);
    } catch (e) {
        // console.warn("Failed to generate cycle stats");
        return [];
    }
  },

  getEmployeeHistory: async (userId: string) => {
    try {
        const cycles = await dbService.getCycles();
        const allNominations = await safeGetDocs(collection(db, 'nominations'));
        const nominations = allNominations.docs.map(d => d.data() as Nomination);

        const allVotes = await safeGetDocs(collection(db, 'votes'));
        const votes = allVotes.docs.map(d => d.data() as Vote);

        const users = await dbService.getUsers();

        return cycles.map(cycle => {
        const myNomination = nominations.find(n => n.cycleId === cycle.id && n.nominatorId === userId);
        const myVote = votes.find(v => v.cycleId === cycle.id && v.voterId === userId);
        const receivedNoms = nominations.filter(n => n.cycleId === cycle.id && n.nomineeId === userId);
        const receivedVotes = votes.filter(v => v.cycleId === cycle.id && v.nomineeId === userId).length;

        const nomineeName = myNomination ? users.find(u => u.id === myNomination.nomineeId)?.name || 'Unknown' : undefined;

        return {
            cycle,
            activity: {
            nominated: myNomination ? { name: nomineeName, reason: myNomination.reason } : null,
            voted: !!myVote,
            receivedNominations: receivedNoms.map(n => ({
                from: users.find(u => u.id === n.nominatorId)?.name || 'Unknown',
                reason: n.reason
            })),
            votesReceived: receivedVotes
            }
        };
        }).sort((a, b) => (b.cycle.year * 12 + b.cycle.month) - (a.cycle.year * 12 + a.cycle.month));
    } catch (e) {
        return [];
    }
  }
};

import React, { useEffect, useState } from 'react';
import { useAuth } from '../context/AuthContext';
import { dbService } from '../services/db';
import { Cycle, CycleStatus, Nomination, Vote } from '../types';
import { Calendar, UserCheck, Vote as VoteIcon, AlertCircle, CheckCircle, WifiOff } from 'lucide-react';
import { Link } from 'react-router-dom';

const MONTHS = [
  'January', 'February', 'March', 'April', 'May', 'June',
  'July', 'August', 'September', 'October', 'November', 'December'
];

export const Dashboard: React.FC = () => {
  const { user } = useAuth();
  const [activeCycle, setActiveCycle] = useState<Cycle | undefined>(undefined);
  const [userNomination, setUserNomination] = useState<Nomination | undefined>(undefined);
  const [userVote, setUserVote] = useState<Vote | undefined>(undefined);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    const loadData = async () => {
      setLoading(true);
      setError(null);
      try {
        const cycle = await dbService.getActiveCycle();
        setActiveCycle(cycle);

        if (user && cycle) {
          try {
            const [nomination, vote] = await Promise.all([
              dbService.getUserNomination(user.id, cycle.id),
              dbService.getUserVote(user.id, cycle.id)
            ]);
            setUserNomination(nomination);
            setUserVote(vote);
          } catch (userDataError) {
             // Silently fail user specific data load if main cycle loaded but permissions block user data
          }
        }
      } catch (error: any) {
        // Only show error if it's strictly not a permission error or if needed
        // Permission errors are now largely suppressed in db.ts to return empty/undefined
        if (error.code !== 'permission-denied') {
             console.error("Error loading dashboard cycle data", error);
             setError("Unable to load dashboard data. Please check your connection.");
        }
      } finally {
        setLoading(false);
      }
    };

    if (user) loadData();
  }, [user]);

  if (loading) {
    return (
        <div className="flex items-center justify-center min-h-[50vh]">
            <div className="text-gray-500 animate-pulse">Loading dashboard...</div>
        </div>
    );
  }

  if (error) {
    return (
      <div className="p-8 text-center bg-white rounded-xl shadow-sm border border-red-100">
        <div className="inline-flex items-center justify-center w-12 h-12 rounded-full bg-red-100 mb-4">
          <WifiOff className="w-6 h-6 text-red-500" />
        </div>
        <h3 className="text-lg font-medium text-gray-900">Connection Error</h3>
        <p className="text-gray-500 mt-2">{error}</p>
        <button 
          onClick={() => window.location.reload()} 
          className="mt-4 px-4 py-2 bg-gray-100 hover:bg-gray-200 text-gray-700 rounded-lg text-sm font-medium transition-colors"
        >
          Retry
        </button>
      </div>
    );
  }

  if (!activeCycle) {
    return (
      <div className="p-8 text-center bg-white rounded-xl shadow-sm">
        <div className="inline-flex items-center justify-center w-12 h-12 rounded-full bg-gray-100 mb-4">
          <Calendar className="w-6 h-6 text-gray-400" />
        </div>
        <h3 className="text-lg font-medium text-gray-900">No Active Cycles</h3>
        <p className="text-gray-500 mt-2">There are currently no active voting cycles. Please check back later.</p>
      </div>
    );
  }

  const getStatusColor = (status: CycleStatus) => {
    switch (status) {
      case CycleStatus.NOMINATION: return 'bg-blue-100 text-blue-800';
      case CycleStatus.VOTING: return 'bg-green-100 text-green-800';
      case CycleStatus.CLOSED: return 'bg-gray-100 text-gray-800';
    }
  };

  return (
    <div className="space-y-6">
      <header className="flex flex-col md:flex-row md:items-center md:justify-between gap-4">
        <div>
          <h1 className="text-2xl font-bold text-gray-900">Welcome, {user?.name}</h1>
          <p className="text-gray-500">Here is your activity for the current cycle.</p>
        </div>
        <div className={`px-4 py-2 rounded-full font-medium text-sm inline-flex items-center self-start ${getStatusColor(activeCycle.status)}`}>
          <Calendar className="w-4 h-4 mr-2" />
          {MONTHS[activeCycle.month]} {activeCycle.year} - {activeCycle.status}
        </div>
      </header>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        {/* Nomination Status Card */}
        <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
          <div className="p-6">
            <div className="flex items-center justify-between mb-4">
              <div className="p-3 bg-indigo-50 rounded-lg">
                <UserCheck className="w-6 h-6 text-indigo-600" />
              </div>
              {userNomination ? (
                <CheckCircle className="w-6 h-6 text-green-500" />
              ) : (
                <div className="w-6 h-6 rounded-full border-2 border-gray-200"></div>
              )}
            </div>
            <h3 className="text-lg font-bold text-gray-900 mb-2">Nomination</h3>
            <p className="text-gray-600 mb-6 min-h-[3rem]">
              {userNomination 
                ? "You have successfully submitted your nomination for this cycle."
                : activeCycle.status === CycleStatus.NOMINATION 
                  ? "Nominate a deserving colleague for their outstanding work."
                  : "Nominations are currently closed for this cycle."
              }
            </p>

            {userNomination ? (
               <button disabled className="w-full py-2 px-4 bg-gray-100 text-gray-400 rounded-lg font-medium cursor-not-allowed">
                 Nomination Submitted
               </button>
            ) : (
              <Link 
                to="/nominate"
                className={`block w-full text-center py-2 px-4 rounded-lg font-medium transition-colors ${
                  activeCycle.status === CycleStatus.NOMINATION
                    ? 'bg-indigo-600 text-white hover:bg-indigo-700'
                    : 'bg-gray-100 text-gray-400 cursor-not-allowed pointer-events-none'
                }`}
              >
                Make a Nomination
              </Link>
            )}
          </div>
        </div>

        {/* Voting Status Card */}
        <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
          <div className="p-6">
            <div className="flex items-center justify-between mb-4">
              <div className="p-3 bg-purple-50 rounded-lg">
                <VoteIcon className="w-6 h-6 text-purple-600" />
              </div>
              {userVote ? (
                <CheckCircle className="w-6 h-6 text-green-500" />
              ) : (
                <div className="w-6 h-6 rounded-full border-2 border-gray-200"></div>
              )}
            </div>
            <h3 className="text-lg font-bold text-gray-900 mb-2">Voting</h3>
            <p className="text-gray-600 mb-6 min-h-[3rem]">
              {userVote
                ? "Thank you for casting your vote."
                : activeCycle.status === CycleStatus.VOTING
                  ? "Cast your vote for the final candidates."
                  : activeCycle.status === CycleStatus.NOMINATION
                    ? "Voting will open once the nomination phase is complete."
                    : "Voting is closed."
              }
            </p>

            {userVote ? (
               <button disabled className="w-full py-2 px-4 bg-gray-100 text-gray-400 rounded-lg font-medium cursor-not-allowed">
                 Vote Submitted
               </button>
            ) : (
              <Link 
                to="/vote"
                className={`block w-full text-center py-2 px-4 rounded-lg font-medium transition-colors ${
                  activeCycle.status === CycleStatus.VOTING
                    ? 'bg-purple-600 text-white hover:bg-purple-700'
                    : 'bg-gray-100 text-gray-400 cursor-not-allowed pointer-events-none'
                }`}
              >
                Cast Vote
              </Link>
            )}
          </div>
        </div>
      </div>

      <div className="bg-blue-50 border border-blue-100 rounded-xl p-4 flex items-start">
        <AlertCircle className="w-5 h-5 text-blue-600 mt-0.5 mr-3 flex-shrink-0" />
        <div>
          <h4 className="font-semibold text-blue-900">How it works</h4>
          <ul className="mt-2 text-sm text-blue-800 list-disc list-inside space-y-1">
            <li>Nominations are anonymous.</li>
            <li>You can only nominate one person per cycle.</li>
            <li>Voting opens after the nomination phase ends.</li>
            <li>You cannot nominate or vote for yourself (System integrity).</li>
          </ul>
        </div>
      </div>
    </div>
  );
};

import React, { useEffect, useState } from 'react';
import { dbService } from '../services/db';
import { Cycle, CycleStatus, CycleStats, User, UserRole } from '../types';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer } from 'recharts';
import { Download, Plus, Play, StopCircle, Archive, Pencil, Power, X, UserPlus, Calendar, Award, MessageSquare, CheckCircle, Vote, Trophy, Lock } from 'lucide-react';

const MONTHS = [
  'January', 'February', 'March', 'April', 'May', 'June',
  'July', 'August', 'September', 'October', 'November', 'December'
];

export const AdminDashboard: React.FC = () => {
  const [activeCycle, setActiveCycle] = useState<Cycle | undefined>();
  const [stats, setStats] = useState<CycleStats[]>([]);
  const [winner, setWinner] = useState<User | null>(null);

  // Cycle Creation State
  const [isCreateCycleModalOpen, setIsCreateCycleModalOpen] = useState(false);
  const [createCycleForm, setCreateCycleForm] = useState({
    month: new Date().getMonth(),
    year: new Date().getFullYear()
  });
  const [createCycleError, setCreateCycleError] = useState('');

  // Employee Management State
  const [users, setUsers] = useState<User[]>([]);
  const [isEditModalOpen, setIsEditModalOpen] = useState(false);
  const [editingUser, setEditingUser] = useState<User | null>(null);

  // Profile View State
  const [viewingUser, setViewingUser] = useState<User | null>(null);
  const [userHistory, setUserHistory] = useState<any[]>([]);

  // Add Employee Modal State
  const [isAddUserModalOpen, setIsAddUserModalOpen] = useState(false);
  const [newUser, setNewUser] = useState({
    name: '',
    email: '',
    department: '',
    role: UserRole.EMPLOYEE,
    password: ''
  });
  const [addUserError, setAddUserError] = useState('');

  const refreshData = async () => {
    try {
      const cycle = await dbService.getActiveCycle();
      setActiveCycle(cycle);
      if (cycle) {
        try {
          const stats = await dbService.getCycleStats(cycle.id);
          setStats(stats || []);
          if (cycle.winnerId) {
            const winnerUser = await dbService.getUserById(cycle.winnerId);
            setWinner(winnerUser || null);
          } else {
            setWinner(null);
          }
        } catch (statError) {
          console.warn("Failed to load cycle stats", statError);
          setStats([]);
        }
      }

      try {
        const allUsers = await dbService.getUsers();
        setUsers(allUsers || []);
      } catch (userError) {
        console.warn("Failed to load users for admin", userError);
        setUsers([]);
      }
    } catch (error) {
      console.error("Failed to load admin data", error);
    }
  };

  useEffect(() => {
    refreshData();
  }, []);

  const handleOpenCreateCycle = () => {
    const now = new Date();
    setCreateCycleForm({ month: now.getMonth(), year: now.getFullYear() });
    setCreateCycleError('');
    setIsCreateCycleModalOpen(true);
  };

  const handleCreateCycleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setCreateCycleError('');

    // Removed restriction for future dates to allow admins to prepare cycles in advance.

    try {
        await dbService.createCycle(createCycleForm.month, createCycleForm.year);
        setIsCreateCycleModalOpen(false);
        refreshData();
    } catch (e: any) {
        setCreateCycleError("Failed to create cycle: " + e.message);
    }
  };

  const updateStatus = async (status: CycleStatus) => {
    if (activeCycle) {
      await dbService.updateCycleStatus(activeCycle.id, status);
      refreshData();
    }
  };

  const handleDeclareWinner = async () => {
    if (!activeCycle || stats.length === 0) return;

    // Assumes stats are sorted by vote count desc
    const leader = stats[0];
    if (leader.voteCount > 0) {
      await dbService.setCycleWinner(activeCycle.id, leader.nomineeId);
      await dbService.updateCycleStatus(activeCycle.id, CycleStatus.CLOSED);
      refreshData();
    }
  };

  const handleExport = async () => {
    if (!activeCycle) return;

    // Convert stats to CSV
    const headers = ['Nominee Name', 'Department', 'Nominations', 'Votes'];
    const users = await dbService.getUsers();

    const rows = stats.map(s => {
      const u = users.find(user => user.id === s.nomineeId);
      return [
        s.nomineeName,
        u?.department || 'N/A',
        s.nominationCount,
        s.voteCount
      ].join(',');
    });

    const csvContent = "data:text/csv;charset=utf-8," + [headers.join(','), ...rows].join('\n');
    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", `results_${MONTHS[activeCycle.month]}_${activeCycle.year}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  // User Management Functions
  const handleEditClick = (user: User) => {
    setEditingUser({ ...user });
    setIsEditModalOpen(true);
  };

  const handleViewProfile = async (user: User) => {
    setViewingUser(user);
    const history = await dbService.getEmployeeHistory(user.id);
    setUserHistory(history);
  };

  const handleUserUpdate = async (e: React.FormEvent) => {
    e.preventDefault();
    if (editingUser) {
      await dbService.updateUser(editingUser);
      setIsEditModalOpen(false);
      setEditingUser(null);
      refreshData();
    }
  };

  const toggleUserStatus = async (user: User) => {
    const newStatus = user.status === 'ACTIVE' ? 'INACTIVE' : 'ACTIVE';
    await dbService.updateUser({ ...user, status: newStatus });
    refreshData();
  };

  const handleAddUserSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setAddUserError('');
    try {
      await dbService.addUser({
        name: newUser.name,
        email: newUser.email,
        department: newUser.department,
        role: newUser.role,
        password: newUser.password || 'password123' // Fallback default
      });
      setIsAddUserModalOpen(false);
      setNewUser({
        name: '',
        email: '',
        department: '',
        role: UserRole.EMPLOYEE,
        password: ''
      });
      refreshData();
    } catch (err: any) {
      setAddUserError(err.message);
    }
  };

  // Helper to render winner card content
  const renderWinnerSection = () => {
    if (winner) {
      return (
        <div className="flex flex-col md:flex-row items-center gap-6">
          <div className="relative">
            {winner.avatar ? (
               <img src={winner.avatar} alt={winner.name} className="w-24 h-24 rounded-full border-4 border-white shadow-lg object-cover" />
            ) : (
               <div className="w-24 h-24 rounded-full bg-yellow-100 flex items-center justify-center text-yellow-600 text-3xl font-bold border-4 border-white shadow-lg">
                 {winner.name.charAt(0)}
               </div>
            )}
            <div className="absolute -bottom-2 -right-2 bg-yellow-400 text-white p-2 rounded-full shadow-md">
              <Trophy className="w-5 h-5 fill-current" />
            </div>
          </div>
          <div className="text-center md:text-left">
            <h3 className="text-3xl font-bold text-white mb-1">{winner.name}</h3>
            <p className="text-indigo-100 text-lg">{winner.department}</p>
            <div className="mt-4 inline-flex items-center px-4 py-1.5 rounded-full bg-white/20 backdrop-blur-sm text-sm font-medium border border-white/30">
              <CheckCircle className="w-4 h-4 mr-2" />
              Official Employee of the Month
            </div>
          </div>
        </div>
      );
    }

    if (stats.length > 0) {
      const leader = stats[0];
      return (
        <div className="flex flex-col md:flex-row items-center justify-between w-full gap-6">
          <div className="flex items-center gap-4">
             <div className="w-16 h-16 rounded-full bg-white/10 flex items-center justify-center text-white text-2xl font-bold backdrop-blur-sm">
                #1
             </div>
             <div>
               <h3 className="text-xl font-bold text-white">Current Leader: {leader.nomineeName}</h3>
               <p className="text-indigo-100">{leader.voteCount} Votes ({Math.round((leader.voteCount / (stats.reduce((acc, c) => acc + c.voteCount, 0) || 1)) * 100)}%)</p>
             </div>
          </div>

          <button 
            onClick={handleDeclareWinner}
            className="px-6 py-3 bg-white text-indigo-600 rounded-xl font-bold shadow-lg hover:bg-gray-50 hover:shadow-xl transition-all active:scale-95 flex items-center"
          >
            <Trophy className="w-5 h-5 mr-2" />
            Declare Winner & Close Cycle
          </button>
        </div>
      );
    }

    return (
      <div className="text-center py-4 w-full">
         <p className="text-indigo-100 text-lg">No votes recorded yet. Wait for voting to begin to see leaders.</p>
      </div>
    );
  };

  return (
    <div className="space-y-8 pb-10">
      {/* Header & Controls */}
      <div className="flex flex-col md:flex-row md:items-center md:justify-between gap-4">
        <div>
          <h1 className="text-2xl font-bold text-gray-900 tracking-tight">Admin Dashboard</h1>
          <p className="text-gray-500 mt-1">Manage voting cycles, view results, and manage employees.</p>
        </div>
        <div className="flex gap-2">
          <button 
            onClick={handleOpenCreateCycle}
            className="flex items-center px-5 py-2.5 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 text-sm font-semibold shadow-sm transition-all active:scale-95"
          >
            <Plus className="w-4 h-4 mr-2" />
            New Cycle
          </button>
        </div>
      </div>

      {/* Cycle Management Card */}
      <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-6">
        <h2 className="text-lg font-bold text-gray-900 mb-4">Current Cycle Status</h2>

        {activeCycle ? (
          <div className="flex flex-col md:flex-row items-center justify-between bg-gray-50 p-5 rounded-xl border border-gray-100">
            <div className="mb-4 md:mb-0">
              <span className="text-xl font-bold text-gray-900 mr-3">
                {MONTHS[activeCycle.month]} {activeCycle.year}
              </span>
              <span className={`px-3 py-1 rounded-full text-xs font-bold uppercase tracking-wide
                ${activeCycle.status === CycleStatus.NOMINATION ? 'bg-blue-100 text-blue-800' : 
                  activeCycle.status === CycleStatus.VOTING ? 'bg-green-100 text-green-800' : 
                  'bg-gray-100 text-gray-800'}`}>
                {activeCycle.status}
              </span>
            </div>

            <div className="flex gap-3">
              {activeCycle.status === CycleStatus.NOMINATION && (
                <button 
                  onClick={() => updateStatus(CycleStatus.VOTING)}
                  className="flex items-center px-4 py-2 bg-purple-600 text-white rounded-lg hover:bg-purple-700 text-sm font-medium transition-colors shadow-sm"
                >
                  <Play className="w-4 h-4 mr-2" />
                  Start Voting
                </button>
              )}
              {activeCycle.status === CycleStatus.VOTING && (
                <button 
                  onClick={() => updateStatus(CycleStatus.CLOSED)}
                  className="flex items-center px-4 py-2 bg-red-600 text-white rounded-lg hover:bg-red-700 text-sm font-medium transition-colors shadow-sm"
                >
                  <StopCircle className="w-4 h-4 mr-2" />
                  Close Cycle
                </button>
              )}
              {activeCycle.status === CycleStatus.CLOSED && (
                <button disabled className="flex items-center px-4 py-2 bg-gray-100 text-gray-400 rounded-lg cursor-not-allowed text-sm font-medium border border-gray-200">
                  <Archive className="w-4 h-4 mr-2" />
                  Archived
                </button>
              )}
            </div>
          </div>
        ) : (
           <div className="text-center py-10 bg-gray-50 rounded-xl border border-dashed border-gray-300 text-gray-500">
             No active cycle found. Create one to begin.
           </div>
        )}
      </div>

      {/* Winner Podium / Leader Section */}
      {activeCycle && (
        <div className="bg-gradient-to-r from-indigo-600 to-purple-600 rounded-2xl shadow-lg overflow-hidden relative">
          <div className="absolute top-0 right-0 p-32 bg-white opacity-5 rounded-full -translate-y-1/2 translate-x-1/2 blur-3xl"></div>
          <div className="absolute bottom-0 left-0 p-20 bg-indigo-900 opacity-10 rounded-full translate-y-1/2 -translate-x-1/2 blur-2xl"></div>

          <div className="p-8 relative z-10">
             <div className="flex items-center gap-2 text-indigo-200 text-sm font-bold uppercase tracking-wider mb-4">
               <Award className="w-4 h-4" />
               {winner ? 'Winner Circle' : 'Projected Winner'}
             </div>
             {renderWinnerSection()}
          </div>
        </div>
      )}

      {/* Results Visualization */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Chart */}
        <div className="lg:col-span-2 bg-white rounded-xl shadow-sm border border-gray-200 p-6">
          <div className="flex items-center justify-between mb-6">
            <h2 className="text-lg font-bold text-gray-900">Real-time Results</h2>
            <button 
              onClick={handleExport}
              disabled={stats.length === 0}
              className="flex items-center text-sm font-medium text-gray-600 hover:text-indigo-600 disabled:opacity-50 transition-colors"
            >
              <Download className="w-4 h-4 mr-1.5" />
              Export CSV
            </button>
          </div>

          {stats.length > 0 ? (
            <div className="h-80 w-full">
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={stats} margin={{ top: 20, right: 30, left: 20, bottom: 5 }}>
                  <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f0f0f0" />
                  <XAxis dataKey="nomineeName" axisLine={false} tickLine={false} tick={{fill: '#6b7280', fontSize: 12}} dy={10} />
                  <YAxis axisLine={false} tickLine={false} allowDecimals={false} tick={{fill: '#6b7280', fontSize: 12}} />
                  <Tooltip 
                    cursor={{ fill: '#f9fafb' }}
                    contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 10px 15px -3px rgba(0, 0, 0, 0.1)' }}
                  />
                  <Legend />
                  <Bar dataKey="nominationCount" name="Nominations" fill="#818cf8" radius={[4, 4, 0, 0]} />
                  <Bar dataKey="voteCount" name="Votes" fill="#4f46e5" radius={[4, 4, 0, 0]} />
                </BarChart>
              </ResponsiveContainer>
            </div>
          ) : (
            <div className="h-80 w-full flex items-center justify-center bg-gray-50 rounded-lg text-gray-400 border border-dashed border-gray-200">
              No data available for this cycle yet.
            </div>
          )}
        </div>

        {/* Top Candidates List */}
        <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-6">
          <h2 className="text-lg font-bold text-gray-900 mb-4">Leaderboard</h2>
          <div className="space-y-3">
            {stats.length > 0 ? (
              stats.slice(0, 5).map((stat, index) => (
                <div key={stat.nomineeId} className="flex items-center p-3 hover:bg-gray-50 rounded-lg transition-colors border border-transparent hover:border-gray-100">
                  <div className={`w-8 h-8 flex items-center justify-center rounded-full font-bold text-sm mr-3 shadow-sm ${
                    index === 0 ? 'bg-yellow-100 text-yellow-700 ring-1 ring-yellow-200' :
                    index === 1 ? 'bg-gray-100 text-gray-700 ring-1 ring-gray-200' :
                    index === 2 ? 'bg-orange-100 text-orange-800 ring-1 ring-orange-200' :
                    'bg-white border text-gray-500'
                  }`}>
                    {index + 1}
                  </div>
                  <div className="flex-1 min-w-0">
                    <p className="text-sm font-semibold text-gray-900 truncate">{stat.nomineeName}</p>
                    <p className="text-xs text-gray-500">{stat.voteCount} votes • {stat.nominationCount} nominations</p>
                  </div>
                  <div className="text-xs font-bold text-indigo-600 bg-indigo-50 px-2.5 py-1 rounded-full">
                    {Math.round((stat.voteCount / (stats.reduce((acc, curr) => acc + curr.voteCount, 0) || 1)) * 100)}%
                  </div>
                </div>
              ))
            ) : (
              <p className="text-sm text-gray-500 text-center py-8">No votes cast yet.</p>
            )}
          </div>
        </div>
      </div>

      {/* Employee Directory Section */}
      <div className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden">
        <div className="p-6 border-b border-gray-200 flex flex-col sm:flex-row sm:items-center justify-between gap-4">
          <div>
            <h2 className="text-lg font-bold text-gray-900">Employee Directory</h2>
            <p className="text-sm text-gray-500 mt-1">Manage user accounts and access.</p>
          </div>
          <button 
            onClick={() => setIsAddUserModalOpen(true)}
            className="flex items-center justify-center px-4 py-2.5 bg-gray-900 text-white rounded-lg hover:bg-gray-800 text-sm font-medium transition-all shadow-sm active:scale-95"
          >
            <UserPlus className="w-4 h-4 mr-2" />
            Add Employee
          </button>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-sm text-left">
            <thead className="bg-gray-50 text-gray-600 font-semibold border-b border-gray-200 uppercase tracking-wider text-xs">
              <tr>
                <th className="px-6 py-4">Name</th>
                <th className="px-6 py-4">Email</th>
                <th className="px-6 py-4">Department</th>
                <th className="px-6 py-4">Role</th>
                <th className="px-6 py-4">Status</th>
                <th className="px-6 py-4 text-right">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-100 bg-white">
              {users.map(user => (
                <tr key={user.id} className="hover:bg-gray-50 transition-colors">
                  <td className="px-6 py-4">
                    <div 
                      onClick={() => handleViewProfile(user)}
                      className="flex items-center cursor-pointer group"
                    >
                      {user.avatar ? (
                        <img 
                          className="h-9 w-9 rounded-full object-cover mr-3 border border-gray-200 group-hover:ring-2 ring-indigo-200 transition-all" 
                          src={user.avatar} 
                          alt={user.name} 
