// Helper to handle Firestore permission errors gracefully
const safeGetDocs = async (q: any) => {
  try {
    return await getDocs(q);
  } catch (error: any) {
    console.error("Firestore query failed:", error.code, error.message);
    throw error;
  }
};

// Database Service with Firestore
export const dbService = {
  seedInitialUsers: async (): Promise<void> => {
    try {
      const batch = writeBatch(db);
      const userColl = collection(db, 'users');

      // Check if users already exist
      const snapshot = await getCountFromServer(userColl);
      if (snapshot.data().count > 0) return;

      console.log("Seeding initial users to Firestore...");

      INITIAL_USERS.forEach(user => {
        const userRef = doc(userColl, user.id); // Use specific IDs if possible, or let Firestore generate
        // Note: We cannot set the Auth password here. This only creates the profile.
        // Users must register or Admin must create Auth accounts separately.
        const userData: User = {
           ...user,
           status: 'ACTIVE'
        };
        // Do not store plain text passwords in Firestore
        if ('password' in userData) delete userData.password;

        batch.set(userRef, userData);
      });

      await batch.commit();
      console.log("Seeding complete.");
    } catch (e) {
      console.error("Failed to seed users", e);
    }
  },

  getUsers: async (): Promise<User[]> => {
    try {
      const snapshot = await safeGetDocs(collection(db, 'users'));

      // Auto-seed if empty
      if (snapshot.empty) {
        await dbService.seedInitialUsers();
        const retrySnapshot = await safeGetDocs(collection(db, 'users'));
        return retrySnapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as User));
      }

      return snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as User));
    } catch (e) {
      console.error("Error getting users:", e);
      return [];
    }
  },

  getUserById: async (id: string): Promise<User | undefined> => {
    const docRef = doc(db, 'users', id);
    try {
      const docSnap = await getDoc(docRef);
      if (docSnap.exists()) {
        return { id: docSnap.id, ...docSnap.data() } as User;
      }
    } catch (error) {
      console.error("Error getting user profile:", error);
    }
    return undefined;
  },

  getEmployees: async (): Promise<User[]> => {
    try {
      // We'll fetch all users and filter client side or use a query
      // Query is better for performance
      const q = query(collection(db, 'users'), where("role", "==", UserRole.EMPLOYEE));
      const snapshot = await safeGetDocs(q);

      if (snapshot.empty) {
         // Fallback to getUsers to trigger seed if totally empty
         const allUsers = await dbService.getUsers();
         return allUsers.filter(u => u.role === UserRole.EMPLOYEE);
      }

      return snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as User));
    } catch (e) {
      return [];
    }
  },

  createUserProfile: async (uid: string, user: Omit<User, 'id' | 'status'>): Promise<void> => {
    let role = user.role;
    try {
      // If first user, make admin
      const coll = collection(db, 'users');
      const snapshot = await getCountFromServer(coll);
      const isFirstUser = snapshot.data().count === 0;
      if (isFirstUser) {
        role = UserRole.ADMIN;
      }
    } catch (error) {
      console.warn("Could not check user count", error);
    }

    const newUserRef = doc(db, 'users', uid);
    const newUser: User = {
      ...user,
      id: uid,
      role: role,
      status: 'ACTIVE'
    };

    if ('password' in newUser) {
      delete newUser.password;
    }

    await setDoc(newUserRef, newUser);
  },

  addUser: async (user: Omit<User, 'id' | 'status'>): Promise<void> => {
    // Check if email exists in Firestore profiles
    const q = query(collection(db, 'users'), where("email", "==", user.email));
    const querySnapshot = await getDocs(q);
    if (!querySnapshot.empty) {
      throw new Error("User with this email already exists in the directory");
    }

    // Create a new document reference with auto-ID
    const newUserRef = doc(collection(db, 'users'));
    const newUser: User = {
      ...user,
      id: newUserRef.id,
      status: 'ACTIVE'
    };

    if ('password' in newUser) {
      delete newUser.password;
    }

    await setDoc(newUserRef, newUser);
  },

  updateUser: async (user: User): Promise<void> => {
    const userRef = doc(db, 'users', user.id);
    const userData = { ...user };
    if ('password' in userData) delete userData.password;
    await updateDoc(userRef, userData);
  },

  getCycles: async (): Promise<Cycle[]> => {
    try {
      const snapshot = await safeGetDocs(collection(db, 'cycles'));
      return snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Cycle));
    } catch (e) {
      console.error("Error getting cycles", e);
      return [];
    }
  },

  getActiveCycle: async (): Promise<Cycle | undefined> => {
    try {
      // Priority 1: Nomination
      const qNom = query(collection(db, 'cycles'), where("status", "==", CycleStatus.NOMINATION));
      const snapNom = await safeGetDocs(qNom);
      if (!snapNom.empty) return { id: snapNom.docs[0].id, ...snapNom.docs[0].data() } as Cycle;

      // Priority 2: Voting
      const qVote = query(collection(db, 'cycles'), where("status", "==", CycleStatus.VOTING));
      const snapVote = await safeGetDocs(qVote);
      if (!snapVote.empty) return { id: snapVote.docs[0].id, ...snapVote.docs[0].data() } as Cycle;

      // Priority 3: Most recent Closed
      const qClosed = query(
          collection(db, 'cycles'), 
          where("status", "==", CycleStatus.CLOSED), 
          orderBy("year", "desc"), 
          orderBy("month", "desc"), 
          limit(1)
      );
      try {
          const snapClosed = await getDocs(qClosed);
          if (!snapClosed.empty) return { id: snapClosed.docs[0].id, ...snapClosed.docs[0].data() } as Cycle;
      } catch (e) {
          // Index might be missing, fail gracefully or handle simple fetch
          console.warn("Index query failed, falling back to simple fetch");
      }
    } catch (error) {
      console.error("Error fetching active cycle", error);
    }
    return undefined;
  },

  createCycle: async (month: number, year: number): Promise<Cycle> => {
    // 1. Close any open cycles first (Best effort)
    try {
        const qOpen = query(collection(db, 'cycles'), where("status", "in", [CycleStatus.NOMINATION, CycleStatus.VOTING]));
        const openSnaps = await getDocs(qOpen);
        const batch = writeBatch(db);
        openSnaps.forEach(doc => {
            batch.update(doc.ref, { status: CycleStatus.CLOSED });
        });
        if (!openSnaps.empty) await batch.commit();
    } catch (e) {
        console.warn("Could not auto-close previous cycles", e);
    }

    // 2. Create new cycle
    const cycleData = {
      month,
      year,
      status: CycleStatus.NOMINATION
    };

    const docRef = await addDoc(collection(db, 'cycles'), cycleData);
    return { id: docRef.id, ...cycleData } as Cycle;
  },

  updateCycleStatus: async (cycleId: string, status: CycleStatus): Promise<void> => {
    const cycleRef = doc(db, 'cycles', cycleId);
    await updateDoc(cycleRef, { status });
  },

  setCycleWinner: async (cycleId: string, winnerId: string): Promise<void> => {
    const cycleRef = doc(db, 'cycles', cycleId);
    await updateDoc(cycleRef, { winnerId });
  },

  getNominations: async (cycleId: string): Promise<Nomination[]> => {
    const q = query(collection(db, 'nominations'), where("cycleId", "==", cycleId));
    const snapshot = await safeGetDocs(q);
    return snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Nomination));
  },

  getUserNomination: async (userId: string, cycleId: string): Promise<Nomination | undefined> => {
    const q = query(
      collection(db, 'nominations'), 
      where("nominatorId", "==", userId),
      where("cycleId", "==", cycleId)
    );
    const snapshot = await safeGetDocs(q);
    if (!snapshot.empty) {
      return { id: snapshot.docs[0].id, ...snapshot.docs[0].data() } as Nomination;
    }
    return undefined;
  },

  addNomination: async (nominatorId: string, nomineeId: string, cycleId: string, reason: string): Promise<void> => {
    const existing = await dbService.getUserNomination(nominatorId, cycleId);
    if (existing) {
      throw new Error("You have already nominated someone this cycle.");
    }

    const nomData = {
      nominatorId,
      nomineeId,
      cycleId,
      reason,
      timestamp: Date.now()
    };
    await addDoc(collection(db, 'nominations'), nomData);
  },

  getVotes: async (cycleId: string): Promise<Vote[]> => {
    const q = query(collection(db, 'votes'), where("cycleId", "==", cycleId));
    const snapshot = await safeGetDocs(q);
    return snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Vote));
  },

  getUserVote: async (userId: string, cycleId: string): Promise<Vote | undefined> => {
    const q = query(
      collection(db, 'votes'), 
      where("voterId", "==", userId),
      where("cycleId", "==", cycleId)
    );
    const snapshot = await safeGetDocs(q);
    if (!snapshot.empty) {
      return { id: snapshot.docs[0].id, ...snapshot.docs[0].data() } as Vote;
    }
    return undefined;
  },

  addVote: async (voterId: string, nomineeId: string, cycleId: string): Promise<void> => {
    const existing = await dbService.getUserVote(voterId, cycleId);
    if (existing) {
      throw new Error("You have already voted this cycle.");
    }

    const voteData = {
      voterId,
      nomineeId,
      cycleId,
      timestamp: Date.now()
    };
    await addDoc(collection(db, 'votes'), voteData);
  },

  getCycleStats: async (cycleId: string): Promise<CycleStats[]> => {
    try {
        const nominations = await dbService.getNominations(cycleId);
        const votes = await dbService.getVotes(cycleId);
        const employees = await dbService.getUsers(); 

        const statsMap = new Map<string, CycleStats>();

        nominations.forEach(nom => {
        if (!statsMap.has(nom.nomineeId)) {
            const emp = employees.find(e => e.id === nom.nomineeId);
            const name = emp ? emp.name : "Employee"; 

            statsMap.set(nom.nomineeId, {
                nomineeId: nom.nomineeId,
                nomineeName: name,
                nominationCount: 0,
                voteCount: 0
            });
        }
        const stat = statsMap.get(nom.nomineeId);
        if (stat) stat.nominationCount++;
        });

        votes.forEach(vote => {
        if (!statsMap.has(vote.nomineeId)) {
            const emp = employees.find(e => e.id === vote.nomineeId);
            const name = emp ? emp.name : "Employee"; 

            statsMap.set(vote.nomineeId, {
                nomineeId: vote.nomineeId,
                nomineeName: name,
                nominationCount: 0,
                voteCount: 0
            });
        }
        const stat = statsMap.get(vote.nomineeId);
        if (stat) stat.voteCount++;
        });

        return Array.from(statsMap.values()).sort((a, b) => b.voteCount - a.voteCount);
    } catch (e) {
        console.error("Stats error", e);
        return [];
    }
  },

  getEmployeeHistory: async (userId: string) => {
    try {
        const cycles = await dbService.getCycles();
        const users = await dbService.getUsers();

        // This is inefficient in Firestore (N+1 queries likely), but for a small internal tool it's okay.
        // Better: Fetch all noms/votes for user in one go if indices allow.

        // Strategy: Get all nominations involved with this user (either nominator or nominee)
        const nomRef = collection(db, 'nominations');
        const voteRef = collection(db, 'votes');

        // We can't easily do "OR" queries across fields in Firestore efficiently without multiple queries
        // Let's just fetch all noms/votes for now or optimize later. 
        // Given the requirement for "history", we'll do simple queries per cycle or global if small.
        // Let's do per cycle map.

        const history = await Promise.all(cycles.map(async cycle => {
             // My nomination
             const myNomQ = query(nomRef, where("cycleId", "==", cycle.id), where("nominatorId", "==", userId));
             const myNomSnap = await getDocs(myNomQ);
             const myNomination = !myNomSnap.empty ? { id: myNomSnap.docs[0].id, ...myNomSnap.docs[0].data() } as Nomination : undefined;

             // My vote
             const myVoteQ = query(voteRef, where("cycleId", "==", cycle.id), where("voterId", "==", userId));
             const myVoteSnap = await getDocs(myVoteQ);
             const myVote = !myVoteSnap.empty;

             // Received Noms
             const recNomQ = query(nomRef, where("cycleId", "==", cycle.id), where("nomineeId", "==", userId));
             const recNomSnap = await getDocs(recNomQ);
             const receivedNoms = recNomSnap.docs.map(d => ({ id: d.id, ...d.data() } as Nomination));

             // Received Votes
             const recVoteQ = query(voteRef, where("cycleId", "==", cycle.id), where("nomineeId", "==", userId));
             const recVoteSnap = await getCountFromServer(recVoteQ);
             const receivedVotes = recVoteSnap.data().count;

             const nomineeName = myNomination ? users.find(u => u.id === myNomination.nomineeId)?.name || 'Unknown' : undefined;

             return {
                cycle,
                activity: {
                    nominated: myNomination ? { name: nomineeName, reason: myNomination.reason } : null,
                    voted: myVote,
                    receivedNominations: receivedNoms.map(n => ({
                        from: users.find(u => u.id === n.nominatorId)?.name || 'Unknown',
                        reason: n.reason
                    })),
                    votesReceived: receivedVotes
                }
             };
        }));

        return history.sort((a, b) => (b.cycle.year * 12 + b.cycle.month) - (a.cycle.year * 12 + a.cycle.month));
    } catch (e) {
        console.error("History error", e);
        return [];
    }
  }
};

import { 
  collection, 
  getDocs, 
  doc, 
  setDoc, 
  updateDoc, 
  query, 
  where, 
  addDoc,
  getDoc,
  writeBatch,
  getCountFromServer,
  orderBy,
  limit
} from "firebase/firestore";
import { db } from "./firebase";
import { User, UserRole, Cycle, CycleStatus, Nomination, Vote, CycleStats } from '../types';
import { mockDb } from './mockDb';

// Helper to handle Firestore permission errors gracefully
const safeGetDocs = async (q: any) => {
  try {
    return await getDocs(q);
  } catch (error: any) {
    // Suppress permission errors in console to avoid noise
    if (error.code !== 'permission-denied') {
        console.warn("Firestore query failed:", error.code, error.message);
    }
    // Return an empty structure that resembles a snapshot to prevent crashes
    return { empty: true, docs: [] };
  }
};

// Database Service with Firestore
export const dbService = {
  getUsers: async (): Promise<User[]> => {
    // Fetch local users
    const localUsers = mockDb.getUsers();

    try {
      // Fetch remote users
      const snapshot = await safeGetDocs(collection(db, 'users'));
      const remoteUsers = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as User));

      // Merge users. If IDs clash (unlikely), prioritize local users as they might have recent edits.
      const userMap = new Map<string, User>();
      remoteUsers.forEach(u => userMap.set(u.id, u));
      localUsers.forEach(u => userMap.set(u.id, u));

      return Array.from(userMap.values());
    } catch (e) {
      // If Firestore fails, return local users
      return localUsers;
    }
  },

  getUserById: async (id: string): Promise<User | undefined> => {
    // Check local mock DB first
    const localUser = mockDb.getUserById(id);
    if (localUser) return localUser;

    const docRef = doc(db, 'users', id);
    try {
      const docSnap = await getDoc(docRef);
      if (docSnap.exists()) {
        return { id: docSnap.id, ...docSnap.data() } as User;
      }
    } catch (error) {
      // Ignore permission errors during profile fetch
    }
    return undefined;
  },

  getEmployees: async (): Promise<User[]> => {
    // Use the merged list from getUsers
    const users = await dbService.getUsers();
    return users.filter(u => u.role === UserRole.EMPLOYEE);
  },

  createUserProfile: async (uid: string, user: Omit<User, 'id' | 'status'>): Promise<void> => {
    // This is used by Register page, still attempts Firestore for real auth users
    let role = user.role;
    try {
      const coll = collection(db, 'users');
      const snapshot = await getCountFromServer(coll);
      const isFirstUser = snapshot.data().count === 0;
      if (isFirstUser) {
        role = UserRole.ADMIN;
      }
    } catch (error) {
      // Silently ignore permission errors for count()
    }

    const newUserRef = doc(db, 'users', uid);
    const newUser: User = {
      ...user,
      id: uid,
      role: role,
      status: 'ACTIVE'
    };

    if ('password' in newUser) {
      delete newUser.password;
    }

    await setDoc(newUserRef, newUser);
