  addUser: async (user: Omit<User, 'id' | 'status'>): Promise<void> => {
    // Use local mockDb for Admin 'Add Employee' to bypass Firestore permission errors
    mockDb.addUser(user);
  },

  updateUser: async (user: User): Promise<void> => {
