const safeGetDocs = async (q: any) => {
  try {
    return await getDocs(q);
  } catch (error: any) {
    console.error("Firestore operation failed:", error.code, error.message);
    // Return empty snapshot-like object to prevents app crash
    return { empty: true, docs: [] };
  }
};

