// Helper to handle Firestore permission errors gracefully
const safeGetDocs = async (q: any) => {
  try {
    return await getDocs(q);
  } catch (error: any) {
    // Silently handle permission denied as it's an expected state for some users/collections
    // depending on security rules.
    if (error.code !== 'permission-denied') {
        console.error("Firestore operation failed:", error.code, error.message);
    }
    return null; // Return null to distinguish from empty snapshot
  }
};

