          </div>

          <button 
            onClick={handleDeclareWinner}
            className="px-6 py-3 bg-white text-indigo-600 rounded-xl font-bold shadow-lg hover:bg-gray-50 hover:shadow-xl transition-all active:scale-95 flex items-center"
