                    >
                      {MONTHS.map((m, idx) => {
                        const now = new Date();
                        const currentYear = now.getFullYear();
                        const currentMonth = now.getMonth();
                        const isFuture = createCycleForm.year > currentYear || (createCycleForm.year === currentYear && idx > currentMonth);

                        return (
                           <option key={idx} value={idx} disabled={isFuture}>
                             {m} {isFuture ? '(Future)' : ''}
                           </option>
